const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.PRODUCTS) || '[]'));
  const [orders, setOrders] = useState<Order[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.ORDERS) || '[]'));
  const [coupons, setCoupons] = useState<Coupon[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.COUPONS) || '[]'));
  const [members, setMembers] = useState<Member[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.MEMBERS) || '[]'));
  const [users, setUsers] = useState<User[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.USERS) || '[]'));
  const [roles, setRoles] = useState<Role[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.ROLES) || '[]'));
  const [storeConfig, setStoreConfig] = useState<StoreConfig>(() => JSON.parse(localStorage.getItem(STORAGE_KEYS.CONFIG) || JSON.stringify(defaultStoreConfig)));

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.SESSION);
    return saved ? JSON.parse(saved) : null;
  });

  const [restockRequests, setRestockRequests] = useState<RestockRequest[]>([]);
  const [isSyncing, setIsSyncing] = useState(false);
  const [stats, setStats] = useState<DashboardStats>({
    todaySales: 0, todayCost: 0, todayProfit: 0, monthlyProfit: 0,
    orderCount: 0, lowStockCount: 0, topProducts: []
  });

  const pullFromCloud = async () => {
    if (!storeConfig.googleSheetsUrl) return;
    setIsSyncing(true);
    try {
      const cloudData = await fetchFromCloud(storeConfig.googleSheetsUrl);
      if (cloudData) {
        if (cloudData.products) setProducts(cloudData.products);
        if (cloudData.members) setMembers(cloudData.members);
        if (cloudData.users) setUsers(cloudData.users);
        if (cloudData.orders) {
          const formatted = cloudData.orders.map((o: any) => ({
            ...o,
            items: typeof (o.items_json || o.items) === 'string' 
              ? JSON.parse(o.items_json || o.items) 
              : (o.items_json || o.items || [])
          }));
          setOrders(formatted);
        }
        if (cloudData.config) setStoreConfig(prev => ({ ...prev, ...cloudData.config }));
      }
    } finally {
      setIsSyncing(false);
    }
  };

  const pushToCloud = async () => {
    if (!storeConfig.googleSheetsUrl) return;
    setIsSyncing(true);
    try {
      await syncToGoogleSheet('SYNC_ALL', {
        products, members, users, config: storeConfig
      }, storeConfig.googleSheetsUrl);
    } finally {
      setIsSyncing(false);
    }
  };

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
    localStorage.setItem(STORAGE_KEYS.ORDERS, JSON.stringify(orders));
    localStorage.setItem(STORAGE_KEYS.MEMBERS, JSON.stringify(members));
    localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users));
    localStorage.setItem(STORAGE_KEYS.ROLES, JSON.stringify(roles));
    localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(storeConfig));

    const palette = THEME_PALETTES[storeConfig.themeColor] || THEME_PALETTES.blue;
    Object.entries(palette).forEach(([shade, hex]) => {
      document.documentElement.style.setProperty(`--color-primary-${shade}`, hex);
    });
  }, [products, orders, members, users, roles, storeConfig]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem(STORAGE_KEYS.SESSION, JSON.stringify(currentUser));
    } else {
      localStorage.removeItem(STORAGE_KEYS.SESSION);
    }
  }, [currentUser]);

  const refreshStats = () => {
    const now = new Date();
    const todayStr = now.toISOString().split('T')[0];
    const monthStr = now.toISOString().slice(0, 7);
    const todayOrders = orders.filter(o => o.timestamp.startsWith(todayStr));
    const monthlyOrders = orders.filter(o => o.timestamp.startsWith(monthStr));
    const calculateOrderCost = (order: Order) => Array.isArray(order.items) ? order.items.reduce((sum, item) => sum + (item.costPrice * item.quantity), 0) : 0;
    const todaySales = todayOrders.reduce((sum, o) => sum + o.total, 0);
    const todayCost = todayOrders.reduce((sum, o) => sum + calculateOrderCost(o), 0);
    const monthlySales = monthlyOrders.reduce((sum, o) => sum + o.total, 0);
    const monthlyCost = monthlyOrders.reduce((sum, o) => sum + calculateOrderCost(o), 0);
    setStats(prev => ({ 
      ...prev, todaySales, todayCost, todayProfit: todaySales - todayCost, 
      monthlyProfit: monthlySales - monthlyCost, orderCount: todayOrders.length, 
      lowStockCount: products.filter(p => p.stock < storeConfig.lowStockThreshold).length 
    }));
  };

  useEffect(() => { refreshStats(); }, [orders, products, storeConfig.lowStockThreshold]);

  const addOrder = (order: Order) => {
    const finalOrder = { ...order, cashierName: currentUser?.name || 'พนักงานขาย' };
    const updatedProducts = products.map(p => {
      const soldItem = finalOrder.items.find(i => i.id === p.id);
      return soldItem ? { ...p, stock: Math.max(0, p.stock - soldItem.quantity) } : p;
    });
    setProducts(updatedProducts);
    setOrders(prev => [finalOrder, ...prev]);

    if (storeConfig.googleSheetsUrl) {
      const readableItems = finalOrder.items.map(i => `${i.name} x${i.quantity}`).join(', ');
      const orderForSync = { 
        ...finalOrder, 
        items: readableItems, 
        items_json: JSON.stringify(finalOrder.items) 
      };
      syncToGoogleSheet('ADD_ORDER', orderForSync, storeConfig.googleSheetsUrl, updatedProducts);
    }
  };

  const deleteOrder = (orderId: string) => {
    const orderToDelete = orders.find(o => o.id === orderId);
    if (!orderToDelete) return;
    const updatedProducts = products.map(p => {
      const returnedItem = Array.isArray(orderToDelete.items) ? orderToDelete.items.find(i => i.id === p.id) : null;
      return returnedItem ? { ...p, stock: p.stock + returnedItem.quantity } : p;
    });
    setProducts(updatedProducts);
    setOrders(prev => prev.filter(o => o.id !== orderId));
    if (storeConfig.googleSheetsUrl) {
      syncToGoogleSheet('DELETE_ORDER', { id: orderId }, storeConfig.googleSheetsUrl, updatedProducts);
    }
  };

  const login = (email: string, pinOrPass: string) => {
    // REAL ADMIN CREDENTIALS
    if (email === 'sahakorn.dbs@gmail.com' && pinOrPass === 'sahakorn1122') {
      setCurrentUser({ id: 'admin', name: 'สหกรณ์ DBS', email, roleId: 'admin' });
      return true;
    }
    const user = users.find(u => u.email === email);
    if (user && user.password === pinOrPass) { 
      setCurrentUser(user); 
      return true; 
    }
    return false;
  };

  return (
    <StoreContext.Provider value={{ 
      products, orders, coupons, members, users, roles, currentUser, restockRequests, storeConfig, 
      addProduct: (p) => setProducts(prev => [...prev, p]), 
      updateProduct: (p) => setProducts(prev => prev.map(old => old.id === p.id ? p : old)), 
      deleteProduct: (id) => setProducts(prev => prev.filter(p => p.id !== id)),
      addOrder, deleteOrder, updateOrderStatus: (id, status) => {
        setOrders(prev => prev.map(o => o.id === id ? { ...o, status } : o));
      }, 
      addCoupon: (c) => setCoupons(prev => [...prev, c]), 
      updateCoupon: (c) => setCoupons(prev => prev.map(old => old.code === c.code ? c : old)), 
      deleteCoupon: (code) => setCoupons(prev => prev.filter(c => c.code !== code)),
      addMember: (m) => setMembers(prev => [...prev, m]), 
      updateMember: (m) => setMembers(prev => prev.map(old => old.id === m.id ? m : old)), 
      deleteMember: (id) => setMembers(prev => prev.filter(m => m.id !== id)),
      addUser: (u) => setUsers(prev => [...prev, u]), 
      updateUser: (u) => setUsers(prev => prev.map(old => old.id === u.id ? u : old)), 
      deleteUser: (id) => setUsers(prev => prev.filter(u => u.id !== id)),
      addRole: (r) => setRoles(prev => [...prev, r]), 
      updateRole: (r) => setRoles(prev => prev.map(old => old.id === r.id ? r : old)), 
      deleteRole: (id) => setRoles(prev => prev.filter(r => r.id !== id)), 
      login, logout: () => setCurrentUser(null),
      addRestockRequest: (r) => setRestockRequests(prev => [...prev, r]), 
      updateConfig: setStoreConfig, stats, refreshStats, 
      currentThemeColorHex: (THEME_PALETTES[storeConfig.themeColor] || THEME_PALETTES.blue)[600],
      pullFromCloud, pushToCloud, isSyncing
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within a StoreProvider");
  return context;
};

