// --- Audio Decoding & Encoding Helpers (Manual Implementation) ---
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, coupons, members, addRestockRequest, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ทั้งหมด');
  const [isScanError, setIsScanError] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Checkout Modal State
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [amountPaid, setAmountPaid] = useState<string>('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // Discount & Loyalty States
  const [manualDiscount, setManualDiscount] = useState<{ value: number; type: 'percent' | 'amount' }>({ value: 0, type: 'amount' });
  const [appliedCoupon, setAppliedCoupon] = useState<string | null>(null);
  const [selectedMember, setSelectedMember] = useState<Member | null>(null);
  const [pointsToRedeem, setPointsToRedeem] = useState<number>(0);
  const [stampsToRedeem, setStampsToRedeem] = useState<number>(0);

  // --- Voice Command States & Refs ---
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // --- Cart Management Functions ---
  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
  }, []);

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        if (delta > 0 && newQty > item.stock) return item;
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  // --- Calculations ---
  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const manualDiscountAmount = manualDiscount.type === 'percent' ? (subtotal * manualDiscount.value) / 100 : manualDiscount.value;
  const appliedCouponData = appliedCoupon ? coupons.find(c => c.code === appliedCoupon) : null;
  const couponDiscountAmount = appliedCouponData ? (appliedCouponData.type === 'percent' ? (subtotal * appliedCouponData.value) / 100 : appliedCouponData.value) : 0;

  let loyaltyDiscountAmount = 0;
  if (storeConfig.loyaltySystem === 'points' && pointsToRedeem > 0) {
      loyaltyDiscountAmount = Math.floor(pointsToRedeem / storeConfig.pointRedemptionRate);
  } else if (storeConfig.loyaltySystem === 'stamps' && stampsToRedeem > 0) {
      const rewardCount = Math.floor(stampsToRedeem / storeConfig.stampsPerReward);
      loyaltyDiscountAmount = rewardCount * storeConfig.stampRewardValue;
  }

  const totalDiscount = manualDiscountAmount + couponDiscountAmount + loyaltyDiscountAmount;
  const tax = ((subtotal - totalDiscount) * storeConfig.taxRate) / 100;
  const total = Math.max(0, subtotal - totalDiscount + tax);
  const change = paymentMethod === 'cash' ? Math.max(0, parseFloat(amountPaid || '0') - total) : 0;

  // --- Order Finalization ---
  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived: number) => {
    const finalChange = pMethod === 'cash' ? Math.max(0, pReceived - total) : 0;

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...cart],
      subtotal,
      discount: totalDiscount,
      discountType: 'amount',
      total,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: pReceived,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total, received: pReceived, change: finalChange };
  }, [cart, total, totalDiscount, subtotal, storeConfig, orders, addOrder]);

  // --- Gemini Live Implementation ---
  const startVoiceSession = async () => {
    if (isVoiceActive) return;

    setIsVoiceActive(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const outCtx = audioContextRef.current;
    const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

    const addToCartTool: FunctionDeclaration = {
      name: 'addToCartByName',
      parameters: {
        type: Type.OBJECT,
        description: 'ค้นหาสินค้าจากชื่อและเพิ่มเข้าตะกร้าสินค้าตามจำนวนที่ระบุ',
        properties: {
          productName: { type: Type.STRING, description: 'ชื่อสินค้าที่ต้องการเพิ่ม' },
          quantity: { type: Type.NUMBER, description: 'จำนวนสินค้า' }
        },
        required: ['productName', 'quantity']
      }
    };

    const checkoutTool: FunctionDeclaration = {
      name: 'processVoiceCheckout',
      parameters: {
        type: Type.OBJECT,
        description: 'ประมวลผลการชำระเงินเมื่อลูกค้าจ่ายเงินสด',
        properties: {
          cashReceived: { type: Type.NUMBER, description: 'จำนวนเงินสดที่ได้รับมา' }
        },
        required: ['cashReceived']
      }
    };

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
            const source = inCtx.createMediaStreamSource(stream);
            const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(s => s.sendRealtimeInput({
                media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
              }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inCtx.destination);
          });
        },
        onmessage: async (message: LiveServerMessage) => {
          // Handle Tool Calls
          if (message.toolCall) {
            for (const fc of message.toolCall.functionCalls) {
              if (fc.name === 'addToCartByName') {
                const { productName, quantity } = fc.args as any;
                const found = products.find(p => p.name.toLowerCase().includes(productName.toLowerCase()));
                if (found) {
                  addToCart(found, quantity);
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `เพิ่ม ${found.name} ${quantity} รายการ ยอดรวมปัจจุบัน ${subtotal + (found.price * quantity)} บาท` } }
                  }));
                } else {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `ไม่พบสินค้าชื่อ ${productName}` } }
                  }));
                }
              } else if (fc.name === 'processVoiceCheckout') {
                const { cashReceived } = fc.args as any;
                const res = finalizeOrder('cash', cashReceived);
                sessionPromise.then(s => s.sendToolResponse({
                  functionResponses: { id: fc.id, name: fc.name, response: { result: `ยอดชำระ ${res.total} บาท รับเงินมา ${res.received} บาท ทอนเงิน ${res.change} บาท เรียบร้อยแล้วค่ะ` } }
                }));
              }
            }
          }

          // Handle Audio Output
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (base64Audio) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
            const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
            const source = outCtx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outCtx.destination);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
            audioSourcesRef.current.add(source);
            source.onended = () => audioSourcesRef.current.delete(source);
          }

          if (message.serverContent?.interrupted) {
            audioSourcesRef.current.forEach(s => s.stop());
            audioSourcesRef.current.clear();
            nextStartTimeRef.current = 0;
          }
        },
        onclose: () => setIsVoiceActive(false),
        onerror: (e) => {
            console.error("Voice Error:", e);
            setIsVoiceActive(false);
        }
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
        systemInstruction: `คุณคือผู้ช่วย POS อัจฉริยะ (DBS POS) ภาษาไทย
        - สรุปยอดเงินและเงินทอนให้ลูกค้าฟังเสมอ
        - สินค้าในร้านมีดังนี้: ${products.map(p => p.name).join(', ')}
        - หากลูกค้าบอกจำนวนเงินสด ให้เรียกฟังก์ชัน processVoiceCheckout
        - หากลูกค้าสั่งสินค้า ให้เรียกฟังก์ชัน addToCartByName`,
        tools: [{ functionDeclarations: [addToCartTool, checkoutTool] }]
      }
    });

    sessionRef.current = await sessionPromise;
  };

  const stopVoiceSession = () => {
    if (sessionRef.current) sessionRef.current.close();
    setIsVoiceActive(false);
  };

  // --- Wake Word Detection (Web Speech API) ---
  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true;
    recognition.lang = 'th-TH';
    recognition.onresult = (event: any) => {
      const text = event.results[event.results.length - 1][0].transcript.trim();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActive) {
        startVoiceSession();
      }
    };
    recognition.start();
    return () => recognition.stop();
  }, [isVoiceActive, products]);

  // --- Manual UI Event Handlers ---
  const handleBarcodeSubmit = (codeOverride?: string) => {
    const term = codeOverride ? codeOverride.trim() : searchQuery.trim();
    if (!term) return;
    const productByBarcode = products.find(p => p.barcode === term);
    if (productByBarcode && productByBarcode.stock > 0) {
      addToCart(productByBarcode);
      setSearchQuery('');
    } else {
      setIsScanError(true);
      setTimeout(() => setIsScanError(false), 2000);
    }
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;
    setIsCheckoutOpen(true);
    setAmountPaid('');
    setCompletedOrder(null);
  };

  // --- Camera QR/Barcode Integration ---
  useEffect(() => {
    let html5QrCode: Html5Qrcode | null = null;
    if (isCameraOpen) {
        setTimeout(() => {
            const element = document.getElementById("reader");
            if (!element) return;
            html5QrCode = new Html5Qrcode("reader");
            html5QrCode.start({ facingMode: "environment" }, { fps: 10, qrbox: 250 }, (text) => {
                handleBarcodeSubmit(text);
                setIsCameraOpen(false);
            }, () => {}).catch(() => setIsCameraOpen(false));
        }, 300);
        return () => { if (html5QrCode?.isScanning) html5QrCode.stop().then(() => html5QrCode?.clear()); };
    }
  }, [isCameraOpen]);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">
      {/* Voice Activity Overlay */}
      {isVoiceActive && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[100] animate-bounce">
           <div className="bg-primary-600 text-white px-6 py-2 rounded-full shadow-2xl flex items-center gap-3 border-2 border-white">
              <Volume2 size={20} className="animate-pulse" />
              <span className="font-black text-sm uppercase tracking-widest">Voice Active</span>
              <button onClick={stopVoiceSession} className="ml-2 hover:bg-white/20 p-1 rounded-full"><X size={16}/></button>
           </div>
        </div>
      )}

      {/* Main Grid: Products */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10">
          <div className="flex flex-col sm:flex-row gap-3 mb-4">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                ref={searchInputRef}
                type="text"
                placeholder="ค้นหา หรือ สแกนบาร์โค้ด..."
                className={`w-full pl-10 pr-12 py-3 border rounded-xl focus:outline-none focus:ring-2 shadow-sm text-lg transition-all ${isScanError ? 'border-red-500 bg-red-50' : 'border-slate-200 focus:ring-primary-500'}`}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleBarcodeSubmit()}
              />
            </div>

            <div className="flex gap-2">
                <button 
                  onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()}
                  className={`px-4 py-2 rounded-xl flex items-center gap-2 shadow-md transition-all active:scale-95 whitespace-nowrap font-bold ${isVoiceActive ? 'bg-red-500 text-white' : 'bg-slate-100 text-slate-700 hover:bg-slate-200'}`}
                >
                  {isVoiceActive ? <MicOff size={20}/> : <Mic size={20}/>}
                  <span className="hidden sm:inline">{isVoiceActive ? 'ปิดไมค์' : 'คำสั่งเสียง'}</span>
                </button>
                <button onClick={() => setIsCameraOpen(true)} className="bg-primary-600 text-white px-4 py-2 rounded-xl flex items-center gap-2 hover:bg-primary-700 shadow-md">
                   <Camera size={20} /> <span className="hidden sm:inline font-bold">กล้อง</span>
                </button>
            </div>
          </div>

          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {['ทั้งหมด', ...new Set(products.map(p => p.category))].map(cat => (
              <button key={cat} onClick={() => setSelectedCategory(cat)} className={`px-4 py-1.5 rounded-full text-sm font-medium whitespace-nowrap transition-all ${selectedCategory === cat ? 'bg-primary-600 text-white shadow-md' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>{cat}</button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-4">
            {products.filter(p => (selectedCategory === 'ทั้งหมด' || p.category === selectedCategory) && (p.name.includes(searchQuery) || p.barcode?.includes(searchQuery))).map(product => (
              <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-3 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-start transition-all relative group ${product.stock === 0 ? 'opacity-50 grayscale' : 'hover:shadow-lg hover:border-primary-200 active:scale-95'}`}>
                <div className="w-full aspect-square bg-slate-50 rounded-xl mb-3 overflow-hidden">
                   <img src={product.image} alt={product.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                </div>
                <h3 className="font-bold text-slate-800 line-clamp-1 text-sm">{product.name}</h3>
                <div className="flex justify-between w-full mt-2 items-center">
                  <span className="font-black text-primary-600">{storeConfig.currency}{product.price.toFixed(2)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold ${product.stock < storeConfig.lowStockThreshold ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-400'}`}>เหลือ {product.stock}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Right Sidebar: Cart */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
            <h2 className="font-black text-lg text-slate-800 flex items-center gap-2"><ShoppingCart size={20}/> ตะกร้าสินค้า</h2>
            <button onClick={() => setCart([])} className="text-xs font-bold text-red-400 hover:text-red-600 px-2 py-1 hover:bg-red-50 rounded transition-colors">ล้างตะกร้า</button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 opacity-40">
              <ShoppingCart size={64} className="mb-4" />
              <p className="font-bold">ตะกร้าว่างเปล่า</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex gap-3 bg-white p-3 rounded-2xl border border-slate-100 shadow-sm animate-in slide-in-from-right-4 duration-300">
                <img src={item.image} className="w-12 h-12 rounded-xl object-cover border" />
                <div className="flex-1 min-w-0">
                  <h4 className="text-xs font-bold text-slate-800 truncate">{item.name}</h4>
                  <div className="text-primary-600 font-black text-sm">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
                </div>
                <div className="flex flex-col items-end gap-2">
                    <div className="flex items-center bg-slate-50 rounded-lg border overflow-hidden">
                        <button onClick={() => updateQuantity(item.id, -1)} className="p-1.5 hover:bg-slate-200"><Minus size={12}/></button>
                        <span className="w-8 text-center text-xs font-black">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="p-1.5 hover:bg-slate-200"><Plus size={12}/></button>
                    </div>
                    <button onClick={() => removeFromCart(item.id)} className="text-slate-300 hover:text-red-500"><Trash2 size={14}/></button>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Footer: Sum */}
        <div className="p-4 bg-slate-900 text-white rounded-t-[2rem] shadow-2xl">
          <div className="space-y-2 mb-6 px-2">
             <div className="flex justify-between text-slate-400 text-sm"><span>รวมราคาสินค้า</span><span>{storeConfig.currency}{subtotal.toFixed(2)}</span></div>
             {totalDiscount > 0 && <div className="flex justify-between text-green-400 text-sm"><span>ส่วนลดทั้งหมด</span><span>-{storeConfig.currency}{totalDiscount.toFixed(2)}</span></div>}
             <div className="flex justify-between text-2xl font-black mt-2 pt-2 border-t border-white/10"><span>ยอดสุทธิ</span><span>{storeConfig.currency}{total.toFixed(2)}</span></div>
          </div>
          <button 
            onClick={handleCheckout} 
            disabled={cart.length === 0} 
            className="w-full bg-primary-500 hover:bg-primary-400 disabled:bg-slate-700 text-white py-4 rounded-2xl font-black text-lg shadow-xl shadow-primary-950/20 transition-all active:scale-[0.98] flex items-center justify-center gap-2"
          >
            <Banknote size={24} /> ชำระเงิน
          </button>
        </div>
      </div>

      {/* Manual Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-300">
            <div className="p-6 bg-slate-50 border-b flex justify-between items-center">
              <h3 className="font-black text-xl text-slate-800">ชำระเงิน</h3>
              <button onClick={() => setIsCheckoutOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors"><X size={24}/></button>
            </div>

            {completedOrder ? (
              <div className="p-10 flex flex-col items-center justify-center text-center space-y-6">
                <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center animate-bounce"><CheckCircle size={56} /></div>
                <div>
                    <h2 className="text-3xl font-black text-slate-800 mb-1">จ่ายสำเร็จ!</h2>
                    <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Order #{completedOrder.id.slice(-6)}</p>
                </div>
                <div className="bg-slate-50 rounded-3xl p-6 w-full border border-slate-100">
                   <p className="text-slate-500 font-bold mb-1">ยอดเงินทอน</p>
                   <span className="font-black text-green-600 text-5xl">{storeConfig.currency}{change.toFixed(2)}</span>
                </div>
                <button onClick={() => setIsCheckoutOpen(false)} className="w-full bg-slate-900 text-white py-5 rounded-3xl font-black text-lg shadow-xl hover:bg-black transition-all">กลับหน้าแรก</button>
              </div>
            ) : (
              <div className="p-8 space-y-6">
                  <div className="text-center bg-slate-50 py-6 rounded-3xl border border-slate-100">
                    <p className="text-slate-400 font-black uppercase text-xs tracking-widest mb-1">ยอดชำระสุทธิ</p>
                    <h1 className="text-5xl font-black text-slate-900">{storeConfig.currency}{total.toFixed(2)}</h1>
                  </div>

                  <div className="space-y-3">
                    <div className="flex justify-between items-end">
                        <label className="text-sm font-black text-slate-500 uppercase tracking-widest ml-1">รับเงินมา</label>
                        <span className="text-[10px] font-bold text-primary-500">กรุณาระบุจำนวนเงิน</span>
                    </div>
                    <div className="relative">
                        <Banknote className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={24} />
                        <input 
                            type="number" 
                            autoFocus 
                            className="w-full pl-14 pr-6 py-5 text-3xl font-black border-2 border-slate-100 rounded-3xl focus:outline-none focus:border-primary-500 focus:ring-4 focus:ring-primary-500/10 transition-all bg-slate-50/50" 
                            value={amountPaid} 
                            onChange={(e) => setAmountPaid(e.target.value)} 
                            placeholder="0.00" 
                        />
                    </div>
                  </div>

                  <div className="grid grid-cols-4 gap-2">
                     {[50, 100, 500, 1000].map(val => (
                         <button key={val} onClick={() => setAmountPaid(val.toString())} className="py-3 bg-slate-100 hover:bg-primary-500 hover:text-white rounded-2xl font-black transition-all text-slate-600 active:scale-95">{val}</button>
                     ))}
                  </div>

                  <div className="flex justify-between items-center bg-green-50 p-6 rounded-3xl border border-green-100">
                      <span className="font-black text-green-700">เงินทอน</span>
                      <span className="text-3xl font-black text-green-600">{storeConfig.currency}{change.toFixed(2)}</span>
                  </div>

                  <button 
                    onClick={() => finalizeOrder('cash', parseFloat(amountPaid || '0'))} 
                    disabled={parseFloat(amountPaid || '0') < total} 
                    className="w-full bg-primary-500 text-white py-5 rounded-[2rem] font-black text-xl shadow-xl shadow-primary-200 disabled:bg-slate-200 disabled:text-slate-400 disabled:shadow-none transition-all active:scale-[0.98]"
                  >
                    ยืนยันชำระเงิน
                  </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Camera Fullscreen Overlay */}
      {isCameraOpen && (
        <div className="fixed inset-0 bg-slate-900/90 z-[110] flex items-center justify-center p-4 backdrop-blur-md">
            <div className="bg-white w-full max-w-lg rounded-[3rem] overflow-hidden relative border-4 border-white/20">
                <div id="reader" className="w-full min-h-[400px] bg-black"></div>
                <div className="absolute top-6 right-6 flex gap-2">
                    <button onClick={() => setIsCameraOpen(false)} className="bg-white/20 backdrop-blur-md p-3 rounded-full text-white hover:bg-white/40 transition-colors"><X size={24} /></button>
                </div>
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex flex-col items-center gap-2">
                    <div className="w-64 h-64 border-2 border-primary-500/50 rounded-3xl animate-pulse"></div>
                    <p className="text-white font-black text-xs uppercase tracking-[0.3em] bg-black/50 px-4 py-2 rounded-full">Scanning Mode</p>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info } from 'lucide-react';
import { Html5Qrcode } from 'html5-qrcode';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Decoding & Encoding Helpers ---
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, coupons, members, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ทั้งหมด');
  const [isScanError, setIsScanError] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Checkout Modal State
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [amountPaid, setAmountPaid] = useState<string>('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // Discount & Loyalty States
  const [manualDiscount, setManualDiscount] = useState<{ value: number; type: 'percent' | 'amount' }>({ value: 0, type: 'amount' });
  const [appliedCoupon, setAppliedCoupon] = useState<string | null>(null);
  const [selectedMember, setSelectedMember] = useState<Member | null>(null);
  const [pointsToRedeem, setPointsToRedeem] = useState<number>(0);
  const [stampsToRedeem, setStampsToRedeem] = useState<number>(0);

  // --- Voice Command States ---
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // --- Cart Management ---
  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
  }, []);

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        if (delta > 0 && newQty > item.stock) return item;
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  // --- Calculations ---
  const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const manualDiscountAmount = manualDiscount.type === 'percent' ? (subtotal * manualDiscount.value) / 100 : manualDiscount.value;
  const appliedCouponData = appliedCoupon ? coupons.find(c => c.code === appliedCoupon) : null;
  const couponDiscountAmount = appliedCouponData ? (appliedCouponData.type === 'percent' ? (subtotal * appliedCouponData.value) / 100 : appliedCouponData.value) : 0;

  let loyaltyDiscountAmount = 0;
  if (storeConfig.loyaltySystem === 'points' && pointsToRedeem > 0) {
      loyaltyDiscountAmount = Math.floor(pointsToRedeem / storeConfig.pointRedemptionRate);
  } else if (storeConfig.loyaltySystem === 'stamps' && stampsToRedeem > 0) {
      const rewardCount = Math.floor(stampsToRedeem / storeConfig.stampsPerReward);
      loyaltyDiscountAmount = rewardCount * storeConfig.stampRewardValue;
  }

  const totalDiscount = manualDiscountAmount + couponDiscountAmount + loyaltyDiscountAmount;
  const tax = ((subtotal - totalDiscount) * storeConfig.taxRate) / 100;
  const total = Math.max(0, subtotal - totalDiscount + tax);
  const change = paymentMethod === 'cash' ? Math.max(0, parseFloat(amountPaid || '0') - total) : 0;

  // --- Order Finalization ---
  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const received = pReceived !== undefined ? pReceived : (pMethod === 'cash' ? parseFloat(amountPaid || '0') : total);
    const finalChange = pMethod === 'cash' ? Math.max(0, received - total) : 0;

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...cart],
      subtotal,
      discount: totalDiscount,
      discountType: 'amount',
      total,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total, received, change: finalChange };
  }, [cart, total, totalDiscount, subtotal, storeConfig, orders, addOrder, amountPaid]);

  // --- Gemini Live Voice Support ---
  const startVoiceSession = async () => {
    if (isVoiceActive) return;
    setIsVoiceActive(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const outCtx = audioContextRef.current;
    const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

    const addToCartTool: FunctionDeclaration = {
      name: 'addToCartByName',
      parameters: {
        type: Type.OBJECT,
        description: 'ค้นหาสินค้าจากชื่อและเพิ่มเข้าตะกร้าสินค้าตามจำนวนที่ระบุ',
        properties: {
          productName: { type: Type.STRING, description: 'ชื่อสินค้า' },
          quantity: { type: Type.NUMBER, description: 'จำนวน' }
        },
        required: ['productName', 'quantity']
      }
    };

    const checkoutTool: FunctionDeclaration = {
      name: 'processVoiceCheckout',
      parameters: {
        type: Type.OBJECT,
        description: 'ประมวลผลการชำระเงินสด',
        properties: { cashReceived: { type: Type.NUMBER, description: 'จำนวนเงินสดที่ได้รับมา' } },
        required: ['cashReceived']
      }
    };

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
            const source = inCtx.createMediaStreamSource(stream);
            const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(s => s.sendRealtimeInput({
                media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
              }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inCtx.destination);
          });
        },
        onmessage: async (message: LiveServerMessage) => {
          if (message.toolCall) {
            for (const fc of message.toolCall.functionCalls) {
              if (fc.name === 'addToCartByName') {
                const { productName, quantity } = fc.args as any;
                const found = products.find(p => p.name.toLowerCase().includes(productName.toLowerCase()));
                if (found) {
                  addToCart(found, quantity);
                  sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: `เพิ่ม ${found.name} เรียบร้อย` } } }));
                }
              } else if (fc.name === 'processVoiceCheckout') {
                const { cashReceived } = fc.args as any;
                const res = finalizeOrder('cash', cashReceived);
                sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: `ทอนเงิน ${res.change} บาท` } } }));
              }
            }
          }
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (base64Audio) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
            const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
            const source = outCtx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outCtx.destination);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
            audioSourcesRef.current.add(source);
          }
        },
        onclose: () => setIsVoiceActive(false),
        onerror: () => setIsVoiceActive(false)
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
        systemInstruction: `คุณคือผู้ช่วย POS (DBS POS) สรุปยอดเงินทอนให้ลูกค้าฟังเสมอ`,
        tools: [{ functionDeclarations: [addToCartTool, checkoutTool] }]
      }
    });
    sessionRef.current = await sessionPromise;
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true;
    recognition.lang = 'th-TH';
    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActive) startVoiceSession();
    };
    recognition.start();
    return () => recognition.stop();
  }, [isVoiceActive]);

  const handleBarcodeSubmit = (codeOverride?: string) => {
    const term = codeOverride ? codeOverride.trim() : searchQuery.trim();
    if (!term) return;
    const found = products.find(p => p.barcode === term);
    if (found && found.stock > 0) {
      addToCart(found);
      setSearchQuery('');
    } else {
      setIsScanError(true);
      setTimeout(() => setIsScanError(false), 2000);
    }
  };

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">
      {/* Voice Status */}
      {isVoiceActive && (
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[100] animate-bounce">
           <div className="bg-primary-600 text-white px-6 py-2 rounded-full shadow-2xl flex items-center gap-3 border-2 border-white">
              <Volume2 size={20} className="animate-pulse" />
              <span className="font-black text-sm uppercase tracking-widest">Listening...</span>
              <button onClick={() => sessionRef.current?.close()} className="ml-2 hover:bg-white/20 p-1 rounded-full"><X size={16}/></button>
           </div>
        </div>
      )}

      {/* Main Grid */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10">
          <div className="flex flex-col sm:flex-row gap-3 mb-4">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                ref={searchInputRef}
                type="text"
                placeholder="ค้นหา หรือ สแกน..."
                className={`w-full pl-10 pr-12 py-3 border rounded-xl focus:outline-none focus:ring-2 shadow-sm text-lg transition-all ${isScanError ? 'border-red-500 bg-red-50' : 'border-slate-200 focus:ring-primary-500'}`}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleBarcodeSubmit()}
              />
            </div>
            <div className="flex gap-2">
                <button onClick={() => isVoiceActive ? sessionRef.current?.close() : startVoiceSession()} className={`px-4 py-2 rounded-xl flex items-center gap-2 shadow-md font-bold transition-all ${isVoiceActive ? 'bg-red-500 text-white' : 'bg-slate-100 text-slate-700 hover:bg-slate-200'}`}>
                  {isVoiceActive ? <MicOff size={20}/> : <Mic size={20}/>}
                  <span className="hidden sm:inline">{isVoiceActive ? 'ปิดไมค์' : 'คำสั่งเสียง'}</span>
                </button>
                <button onClick={() => setIsCameraOpen(true)} className="bg-primary-600 text-white px-4 py-2 rounded-xl flex items-center gap-2 hover:bg-primary-700 shadow-md">
                   <Camera size={20} /> <span className="hidden sm:inline font-bold">กล้อง</span>
                </button>
            </div>
          </div>
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {['ทั้งหมด', ...new Set(products.map(p => p.category))].map(cat => (
              <button key={cat} onClick={() => setSelectedCategory(cat)} className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${selectedCategory === cat ? 'bg-primary-600 text-white shadow-md' : 'bg-slate-100 text-slate-600'}`}>{cat}</button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-4">
            {products.filter(p => (selectedCategory === 'ทั้งหมด' || p.category === selectedCategory) && (p.name.includes(searchQuery) || p.barcode?.includes(searchQuery))).map(product => (
              <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-3 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-start transition-all relative group ${product.stock === 0 ? 'opacity-50 grayscale' : 'hover:shadow-lg hover:border-primary-200 active:scale-95'}`}>
                <div className="w-full aspect-square bg-slate-50 rounded-xl mb-3 overflow-hidden">
                   <img src={product.image} className="w-full h-full object-cover" />
                </div>
                <h3 className="font-bold text-slate-800 line-clamp-1 text-sm">{product.name}</h3>
                <div className="flex justify-between w-full mt-2 items-center">
                  <span className="font-black text-primary-600">{storeConfig.currency}{product.price.toFixed(2)}</span>
                  <span className="text-[10px] px-2 py-0.5 rounded-full font-bold bg-slate-100 text-slate-400">เหลือ {product.stock}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-4 border-b border-slate-100 flex justify-between bg-slate-50">
            <h2 className="font-black text-lg text-slate-800 flex items-center gap-2"><ShoppingCart size={20}/> ตะกร้าสินค้า</h2>
            <button onClick={() => setCart([])} className="text-xs font-bold text-red-400 px-2 py-1">ล้าง</button>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 opacity-40">
              <ShoppingCart size={64} className="mb-4" />
              <p className="font-bold">ตะกร้าว่างเปล่า</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex gap-3 bg-white p-3 rounded-2xl border border-slate-100 shadow-sm">
                <img src={item.image} className="w-12 h-12 rounded-xl object-cover border" />
                <div className="flex-1 min-w-0">
                  <h4 className="text-xs font-bold text-slate-800 truncate">{item.name}</h4>
                  <div className="text-primary-600 font-black text-sm">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
                </div>
                <div className="flex flex-col items-end gap-2">
                    <div className="flex items-center bg-slate-50 rounded-lg border overflow-hidden">
                        <button onClick={() => updateQuantity(item.id, -1)} className="p-1.5"><Minus size={12}/></button>
                        <span className="w-8 text-center text-xs font-black">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="p-1.5"><Plus size={12}/></button>
                    </div>
                </div>
              </div>
            ))
          )}
        </div>
        <div className="p-4 bg-slate-900 text-white rounded-t-[2rem] shadow-2xl">
          <div className="space-y-2 mb-6 px-2">
             <div className="flex justify-between text-slate-400 text-sm"><span>รวม</span><span>{storeConfig.currency}{subtotal.toFixed(2)}</span></div>
             <div className="flex justify-between text-2xl font-black mt-2 pt-2 border-t border-white/10"><span>ยอดสุทธิ</span><span>{storeConfig.currency}{total.toFixed(2)}</span></div>
          </div>
          <button onClick={() => setIsCheckoutOpen(true)} disabled={cart.length === 0} className="w-full bg-primary-500 hover:bg-primary-400 disabled:bg-slate-700 text-white py-4 rounded-2xl font-black text-lg shadow-xl transition-all">
            <Banknote size={24} className="inline mr-2" /> ชำระเงิน
          </button>
        </div>
      </div>

      {/* Manual Checkout Modal (RESTORED PANEL) */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in zoom-in-95 duration-300">
            {/* Left: Summary & Payment Selection */}
            <div className="flex-1 p-8 border-r border-slate-100">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-black text-xl text-slate-800">ชำระเงิน</h3>
                {!completedOrder && <button onClick={() => setIsCheckoutOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors"><X size={24}/></button>}
              </div>

              {completedOrder ? (
                <div className="h-full flex flex-col items-center justify-center text-center space-y-6 py-10">
                  <div className="w-24 h-24 bg-green-100 text-green-600 rounded-full flex items-center justify-center animate-bounce"><CheckCircle size={56} /></div>
                  <h2 className="text-3xl font-black text-slate-800">จ่ายสำเร็จ!</h2>
                  <div className="bg-slate-50 rounded-3xl p-6 w-full border border-slate-100">
                     <p className="text-slate-500 font-bold mb-1">เงินทอน</p>
                     <span className="font-black text-green-600 text-5xl">{storeConfig.currency}{change.toFixed(2)}</span>
                  </div>
                  <button onClick={() => {setIsCheckoutOpen(false); setCompletedOrder(null);}} className="w-full bg-slate-900 text-white py-5 rounded-3xl font-black text-lg">กลับหน้าแรก</button>
                </div>
