                              autoFocus 
                              className="w-full pl-14 pr-6 py-5 text-3xl font-black border-2 border-slate-100 rounded-3xl focus:outline-none focus:border-primary-500 bg-slate-50/50" 
                              value={amountPaid} 
                              onChange={(e) => setAmountPaid(e.target.value)} 
                              placeholder="0.00" 
                          />
