                        <div className="aspect-square flex flex-col items-center justify-center text-orange-200 gap-2"><Wallet size={48}/><span className="text-xs">ไม่ได้ตั้งค่า QR</span></div>
                      )}
                    </div>
                    <p className="text-sm font-black text-orange-600">ชำระผ่าน TrueMoney</p>
                  </div>
                )}

                {['card', 'ewallet'].includes(paymentMethod) && (
                  <div className="space-y-2">
                    <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto text-slate-300"><Info size={32}/></div>
                    <p className="text-xs font-bold text-slate-400">กรุณาทำรายการผ่านเครื่องรูดบัตรหรือแอปพลิเคชันภายนอกก่อนกดยืนยัน</p>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      )}

      {/* Camera UI */}
      {isCameraOpen && (
        <div className="fixed inset-0 bg-slate-900/90 z-[110] flex items-center justify-center p-4 backdrop-blur-md">
            <div className="bg-white w-full max-w-lg rounded-[3rem] overflow-hidden relative border-4 border-white/20">
                <div id="reader" className="w-full min-h-[400px] bg-black"></div>
                <button onClick={() => setIsCameraOpen(false)} className="absolute top-6 right-6 bg-white/20 p-3 rounded-full text-white"><X size={24} /></button>
            </div>
        </div>
      )}
    </div>
  );
};

