// --- Audio Helpers ---
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, coupons, members, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  // Sync cart to ref for AI tools to overcome closure issues
  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ทั้งหมด');
  const [isScanError, setIsScanError] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Checkout Modal State
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [amountPaid, setAmountPaid] = useState<string>('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // Discount States
  const [manualDiscount, setManualDiscount] = useState<{ value: number; type: 'percent' | 'amount' }>({ value: 0, type: 'amount' });
  const [appliedCoupon, setAppliedCoupon] = useState<string | null>(null);

  // --- Voice Command States ---
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // --- Cart Management ---
  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
  }, []);

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        if (delta > 0 && newQty > item.stock) return item;
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  // --- Calculations ---
  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);
  const totalDiscount = useMemo(() => {
    const manualAmt = manualDiscount.type === 'percent' ? (subtotal * manualDiscount.value) / 100 : manualDiscount.value;
    const couponAmt = appliedCoupon ? (coupons.find(c => c.code === appliedCoupon)?.value || 0) : 0;
    return manualAmt + couponAmt;
  }, [subtotal, manualDiscount, appliedCoupon, coupons]);

  const total = useMemo(() => Math.max(0, subtotal - totalDiscount), [subtotal, totalDiscount]);
  const change = paymentMethod === 'cash' ? Math.max(0, parseFloat(amountPaid || '0') - total) : 0;

  // --- Order Finalization ---
  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    // CRITICAL: use the latest cart from cartRef if called from async tool, or cart from state if UI
    const finalCart = cartRef.current.length > 0 ? cartRef.current : cart;
    if (finalCart.length === 0) return { total: 0, received: 0, change: 0, error: 'Cart is empty' };

    const finalSubtotal = finalCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const finalTotal = Math.max(0, finalSubtotal - totalDiscount);
    const received = pReceived !== undefined ? pReceived : (pMethod === 'cash' ? parseFloat(amountPaid || '0') : finalTotal);
    const finalChange = pMethod === 'cash' ? Math.max(0, received - finalTotal) : 0;

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...finalCart],
      subtotal: finalSubtotal,
      discount: totalDiscount,
      discountType: 'amount',
      total: finalTotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(), // This will be used for reporting
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total: finalTotal, received, change: finalChange };
  }, [cart, totalDiscount, storeConfig.queueEnabled, orders.length, addOrder, amountPaid]);

  // --- Gemini Live Voice Session ---
  const stopVoiceSession = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    setIsVoiceActive(false);
    if (recognitionRef.current) {
      try { recognitionRef.current.start(); } catch (e) {}
    }
  }, [isVoiceActive]);

  const startVoiceSession = async () => {
    if (isVoiceActive) return;
    setIsVoiceActive(true);

    if (recognitionRef.current) {
      try { recognitionRef.current.stop(); } catch (e) {}
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    const outCtx = audioContextRef.current;
    const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

    const addToCartTool: FunctionDeclaration = {
      name: 'addToCartByName',
      parameters: {
        type: Type.OBJECT,
        description: 'ค้นหาชื่อสินค้าและเพิ่มเข้าตะกร้า',
        properties: {
          productName: { type: Type.STRING, description: 'ชื่อสินค้า' },
          quantity: { type: Type.NUMBER, description: 'จำนวน' }
        },
        required: ['productName', 'quantity']
      }
    };

    const checkoutTool: FunctionDeclaration = {
      name: 'processVoiceCheckout',
      parameters: {
        type: Type.OBJECT,
        description: 'ชำระเงินตามช่องทางที่ระบุ',
        properties: {
          cashReceived: { type: Type.NUMBER, description: 'เงินสดที่รับมา' },
          paymentMethod: { type: Type.STRING, enum: ['cash', 'promptpay', 'transfer'] }
        },
        required: ['paymentMethod']
      }
    };

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
            const source = inCtx.createMediaStreamSource(stream);
            const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(s => s.sendRealtimeInput({
                media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
              }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inCtx.destination);
          });
        },
        onmessage: async (message: LiveServerMessage) => {
          if (message.toolCall) {
            for (const fc of message.toolCall.functionCalls) {
              if (fc.name === 'addToCartByName') {
                const { productName, quantity } = fc.args as any;
                const found = products.find(p => p.name.toLowerCase().includes(productName.toLowerCase()));
                if (found) {
                  addToCart(found, quantity);
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `เพิ่ม ${found.name} สำเร็จ` } }
                  }));
                } else {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `ไม่พบสินค้า ${productName}` } }
                  }));
                }
              } else if (fc.name === 'processVoiceCheckout') {
                const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                setPaymentMethod(pMethod);
                const res = finalizeOrder(pMethod, cashReceived);

                let responseText = `ชำระผ่าน ${pMethod} เรียบร้อย ยอดรวม ${res.total} บาท`;
                if (pMethod === 'cash') responseText += ` รับมา ${res.received} ทอน ${res.change} บาท`;

                sessionPromise.then(s => s.sendToolResponse({
                  functionResponses: { id: fc.id, name: fc.name, response: { result: responseText } }
                }));
              }
            }
          }
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (base64Audio) {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
            const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
            const source = outCtx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outCtx.destination);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
            audioSourcesRef.current.add(source);
          }
        },
        onclose: () => setIsVoiceActive(false),
        onerror: () => setIsVoiceActive(false)
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
        systemInstruction: `คุณคือพนักงานขายอัจฉริยะ DBS POS
        - สั่งสินค้า: ใช้ addToCartByName
        - ชำระเงิน: ใช้ processVoiceCheckout (รองรับ จ่ายสด, พร้อมเพย์, โอนเงิน)
        - สรุปยอดรวมและเงินทอนให้ลูกค้าฟังเสมอ`,
        tools: [{ functionDeclarations: [addToCartTool, checkoutTool] }]
      }
    });
    sessionRef.current = await sessionPromise;
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true;
    recognition.lang = 'th-TH';
    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActive) startVoiceSession();
    };
    recognition.onend = () => { if (!isVoiceActive) try { recognition.start(); } catch (err) {} };
    recognition.start();
    recognitionRef.current = recognition;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, [isVoiceActive]);

  const handleBarcodeSubmit = () => {
    const found = products.find(p => p.barcode === searchQuery.trim());
    if (found && found.stock > 0) {
      addToCart(found);
      setSearchQuery('');
    } else {
      setIsScanError(true);
      setTimeout(() => setIsScanError(false), 2000);
    }
  };

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">
      {/* Voice Mode Visual Overly */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[100] flex flex-col items-center justify-center animate-in fade-in duration-300">
           <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl flex flex-col items-center gap-8 border-4 border-primary-500 animate-in zoom-in-95">
              <div className="w-24 h-24 bg-primary-600 rounded-full flex items-center justify-center animate-pulse shadow-xl shadow-primary-200">
                 <Mic size={48} className="text-white" />
              </div>
              <div className="text-center">
                 <h2 className="text-2xl font-black text-slate-800 mb-2">ระบบกำลังฟัง...</h2>
                 <p className="text-slate-500 font-bold italic">"สั่งสินค้า หรือ สั่งคิดเงินสดได้เลย"</p>
              </div>
              <button onClick={stopVoiceSession} className="px-10 py-4 bg-red-50 text-red-600 rounded-full font-black text-lg hover:bg-red-100 transition-all active:scale-95 shadow-lg">ปิดไมค์</button>
           </div>
        </div>
      )}

      {/* Main Grid: Products */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10 border-b border-slate-100">
          <div className="flex flex-col sm:flex-row gap-3 mb-4">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="text"
                placeholder="ค้นหา หรือ สแกน..."
                className={`w-full pl-10 pr-12 py-3 border rounded-xl focus:outline-none focus:ring-2 shadow-sm text-lg transition-all ${isScanError ? 'border-red-500 bg-red-50' : 'border-slate-200 focus:ring-primary-500'}`}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleBarcodeSubmit()}
              />
            </div>
            <div className="flex gap-2">
                <button onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} className={`px-5 py-2 rounded-xl flex items-center gap-2 font-black text-sm border-2 transition-all shadow-md active:scale-95 ${isVoiceActive ? 'border-primary-500 bg-primary-50 text-primary-600' : 'border-slate-200 bg-white text-slate-700 hover:border-primary-200'}`}>
                   {isVoiceActive ? <MicOff size={20} /> : <Sparkles size={18} className="text-primary-500" />}
                   <span>{isVoiceActive ? 'ปิดไมค์' : 'คำสั่งเสียง'}</span>
                </button>
                <button onClick={() => setIsCameraOpen(true)} className="bg-slate-900 text-white px-5 py-2 rounded-xl flex items-center gap-2 hover:bg-black shadow-md transition-all active:scale-95"><Camera size={20} /> สแกน</button>
            </div>
          </div>

          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {['ทั้งหมด', ...new Set(products.map(p => p.category))].map(cat => (
              <button key={cat} onClick={() => setSelectedCategory(cat)} className={`px-5 py-1.5 rounded-full text-sm font-bold transition-all shadow-sm border ${selectedCategory === cat ? 'bg-primary-600 text-white border-primary-600 shadow-primary-100' : 'bg-white text-slate-500 border-slate-100 hover:bg-slate-50'}`}>{cat}</button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-5">
            {products.filter(p => (selectedCategory === 'ทั้งหมด' || p.category === selectedCategory) && (p.name.includes(searchQuery) || p.barcode?.includes(searchQuery))).map(product => (
              <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-4 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col items-start transition-all relative group ${product.stock === 0 ? 'opacity-50 grayscale' : 'hover:shadow-xl hover:border-primary-100 active:scale-95'}`}>
                <div className="w-full aspect-square bg-slate-50 rounded-2xl mb-4 overflow-hidden border border-slate-50">
                   <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                </div>
                <h3 className="font-bold text-slate-800 line-clamp-1 text-sm">{product.name}</h3>
                <div className="flex justify-between w-full mt-2 items-center">
                  <span className="font-black text-primary-600 text-base">{storeConfig.currency}{product.price.toFixed(2)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full font-black uppercase ${product.stock < storeConfig.lowStockThreshold ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>สต็อก {product.stock}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Sidebar Cart */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-5 border-b border-slate-100 flex justify-between bg-slate-50/40">
            <h2 className="font-black text-xl text-slate-800 flex items-center gap-2"><ShoppingCart size={22} className="text-primary-600"/> ตะกร้า</h2>
            <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:text-red-600 px-3 py-1.5 bg-red-50 rounded-full uppercase transition-all">ล้าง</button>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-3">
          {cart.map(item => (
            <div key={item.id} className="flex gap-4 bg-white p-4 rounded-[1.8rem] border border-slate-50 shadow-sm hover:shadow-md transition-all">
              <img src={item.image} className="w-14 h-14 rounded-2xl object-cover border border-slate-100 shadow-sm" />
              <div className="flex-1 min-w-0">
                <h4 className="text-xs font-black text-slate-800 truncate">{item.name}</h4>
                <div className="text-primary-600 font-black text-base">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
              </div>
              <div className="flex flex-col items-end gap-2">
                  <div className="flex items-center bg-slate-50 rounded-xl border border-slate-200 overflow-hidden shadow-inner">
                      <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-white transition-colors"><Minus size={12}/></button>
                      <span className="w-8 text-center text-xs font-black">{item.quantity}</span>
                      <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-white transition-colors"><Plus size={12}/></button>
                  </div>
              </div>
            </div>
          ))}
        </div>
        <div className="p-6 bg-slate-900 text-white rounded-t-[3.5rem] shadow-2xl">
          <div className="space-y-3 mb-6 px-2">
             <div className="flex justify-between text-slate-400 text-sm font-bold uppercase tracking-widest"><span>ยอดรวม</span><span>{storeConfig.currency}{subtotal.toFixed(2)}</span></div>
             <div className="flex justify-between text-3xl font-black mt-2 pt-4 border-t border-white/10 tracking-tight"><span>สุทธิ</span><span>{storeConfig.currency}{total.toFixed(2)}</span></div>
          </div>
          <button onClick={() => setIsCheckoutOpen(true)} disabled={cart.length === 0} className="w-full bg-primary-500 hover:bg-primary-400 disabled:bg-slate-800 disabled:text-slate-600 text-white py-5 rounded-[2.2rem] font-black text-xl shadow-xl transition-all active:scale-[0.98] flex items-center justify-center gap-3 uppercase tracking-wider">
            <Banknote size={26} /> ชำระเงิน
          </button>
        </div>
      </div>

      {/* Manual Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in zoom-in-95 duration-300">
            <div className="flex-1 p-8 border-r border-slate-100">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-black text-2xl text-slate-800 tracking-tight">จ่ายเงิน</h3>
                {!completedOrder && <button onClick={() => setIsCheckoutOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400"><X size={28}/></button>}
              </div>

              {completedOrder ? (
                <div className="h-full flex flex-col items-center justify-center text-center space-y-8 py-10 animate-in fade-in">
                  <div className="w-28 h-28 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce shadow-lg shadow-emerald-100"><CheckCircle size={64} /></div>
                  <h2 className="text-4xl font-black text-slate-800 mb-2">สำเร็จ!</h2>
                  <div className="bg-slate-50 rounded-[2.5rem] p-8 w-full border border-slate-100 shadow-inner">
                     <p className="text-slate-500 font-black text-xs uppercase tracking-[0.2em] mb-2">เงินทอน</p>
                     <span className="font-black text-emerald-600 text-6xl">{storeConfig.currency}{change.toFixed(2)}</span>
