                  <div className="text-center bg-slate-50 py-8 rounded-[2.8rem] border border-slate-100 shadow-inner">
                    <p className="text-slate-400 font-black uppercase text-[10px] tracking-[0.3em] mb-2">ยอดที่ต้องชำระ</p>
