                  <div className="grid grid-cols-3 gap-3">
                    {[
                      { id: 'cash', label: 'เงินสด', icon: Banknote },
                      { id: 'promptpay', label: 'พร้อมเพย์', icon: QrCode },
                      { id: 'transfer', label: 'โอนเงิน', icon: Landmark },
                    ].map(method => (
                      <button 
