                        autoFocus 
                        className="w-full px-8 py-6 text-4xl font-black border-2 border-slate-100 rounded-[2.2rem] focus:outline-none focus:border-primary-500 bg-slate-50 shadow-inner tracking-tight" 
                        value={amountPaid} 
                        onChange={(e) => setAmountPaid(e.target.value)} 
                        placeholder="0.00" 
                      />
                    </div>
                  )}

                  <button 
                    onClick={() => finalizeOrder(paymentMethod)} 
                    disabled={paymentMethod === 'cash' && parseFloat(amountPaid || '0') < total} 
                    className="w-full bg-primary-600 text-white py-6 rounded-[2.2rem] font-black text-2xl shadow-xl shadow-primary-100 transition-all active:scale-[0.98] disabled:bg-slate-100 disabled:text-slate-300 disabled:shadow-none uppercase tracking-widest"
                  >
                    ยืนยัน
                  </button>
                </div>
              )}
            </div>
            <div className="w-full md:w-80 bg-slate-50/80 p-8 flex flex-col justify-center items-center text-center border-t md:border-t-0 md:border-l border-slate-100 backdrop-blur-sm">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">ข้อมูลการชำระเงิน</p>
                <div className="p-6 bg-white rounded-[2.2rem] border border-slate-200 shadow-sm w-full mt-4">
                   <p className="text-[10px] text-slate-300 font-black mb-1 uppercase tracking-widest">เงินทอน</p>
                   <p className="text-4xl font-black text-primary-600 tracking-tight">{storeConfig.currency}{change.toFixed(2)}</p>
                </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

