import React, { useState, useMemo } from 'react';
import { useStore } from '../context/StoreContext';
import { FileSpreadsheet, Download, Calendar, Filter, Search, TrendingUp, DollarSign, Wallet, PiggyBank } from 'lucide-react';

interface ReportItem {
  id: string;
  name: string;
  quantity: number;
  costPrice: number;
  salePrice: number;
  totalRevenue: number;
  totalCost: number;
  profitPerUnit: number;
  totalProfit: number;
}

const SalesReport: React.FC = () => {
  const { orders, storeConfig } = useStore();
  const [viewMode, setViewMode] = useState<'daily' | 'monthly'>('daily');

  // Use local date for initial values
  const [selectedDate, setSelectedDate] = useState(new Date().toLocaleDateString('en-CA'));
  const [selectedMonth, setSelectedMonth] = useState(new Date().toLocaleDateString('en-CA').slice(0, 7));
  const [searchQuery, setSearchQuery] = useState('');

  // 1. Filter orders based on selected period using Local Time match
  const filteredOrders = useMemo(() => {
    return orders.filter(order => {
      // order.timestamp comes from .toISOString() which is UTC, 
      // but we match prefix which corresponds to the YYYY-MM-DD local format used in addOrder
      const orderDate = order.timestamp.split('T')[0];
      const orderMonth = order.timestamp.slice(0, 7);

      if (viewMode === 'daily') {
        return orderDate === selectedDate;
      } else {
        return orderMonth === selectedMonth;
      }
    });
  }, [orders, viewMode, selectedDate, selectedMonth]);

  // 2. Aggregate items from filtered orders
  const reportData = useMemo(() => {
    const itemMap = new Map<string, ReportItem>();

    filteredOrders.forEach(order => {
      if (!Array.isArray(order.items)) return;
      order.items.forEach(item => {
        const existing = itemMap.get(item.id);
        const cost = item.costPrice || 0;
        const price = item.price || 0;

        if (existing) {
          existing.quantity += item.quantity;
          existing.totalRevenue += price * item.quantity;
          existing.totalCost += cost * item.quantity;
          existing.totalProfit += (price - cost) * item.quantity;
        } else {
          itemMap.set(item.id, {
            id: item.id,
            name: item.name,
            quantity: item.quantity,
            costPrice: cost,
            salePrice: price,
            totalRevenue: price * item.quantity,
            totalCost: cost * item.quantity,
            profitPerUnit: price - cost,
            totalProfit: (price - cost) * item.quantity
          });
        }
      });
    });

    let results = Array.from(itemMap.values());
    if (searchQuery) {
      results = results.filter(item => item.name.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    return results.sort((a, b) => b.totalRevenue - a.totalRevenue); // Sort by highest revenue
  }, [filteredOrders, searchQuery]);

  // 3. Totals for summary
  const totals = useMemo(() => {
    return reportData.reduce((acc, item) => ({
      quantity: acc.quantity + item.quantity,
      revenue: acc.revenue + item.totalRevenue,
      cost: acc.cost + item.totalCost,
      profit: acc.profit + item.totalProfit
    }), { quantity: 0, revenue: 0, cost: 0, profit: 0 });
  }, [reportData]);

  const handleExportExcel = () => {
    const headers = ['ลำดับ', 'รายการสินค้า', 'จำนวน', 'ต้นทุนรวม', 'ราคาขายรวม', 'กำไรรวม'];
    const rows = reportData.map((item, index) => [
      index + 1, item.name, item.quantity, item.totalCost.toFixed(2), item.totalRevenue.toFixed(2), item.totalProfit.toFixed(2)
    ]);
    const csvContent = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob(['\ufeff' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `Report_${selectedDate}.csv`;
    link.click();
  };

  return (
    <div className="p-6 bg-slate-50 h-full overflow-y-auto">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            <FileSpreadsheet className="text-primary-600" /> รายงานสรุปการขาย
          </h1>
