                  <h2 className="text-5xl font-black text-slate-900 tracking-tight">ชำระสำเร็จ!</h2>
                  <div className="bg-slate-50 rounded-[3rem] p-10 border border-slate-100 shadow-inner">
                     <p className="text-slate-500 font-black text-sm uppercase tracking-[0.3em] mb-3">เงินทอน</p>
                     <span className="font-black text-emerald-600 text-7xl tracking-tighter">{storeConfig.currency}{completedOrder.change?.toFixed(2)}</span>
                  </div>
                  <button onClick={() => {setIsCheckoutOpen(false); setCompletedOrder(null);}} className="w-full bg-slate-900 text-white py-8 rounded-[2.8rem] font-black text-2xl shadow-2xl active:scale-95 uppercase tracking-widest">รายการถัดไป</button>
                </div>
              ) : (
                <div className="space-y-8">
                  <h3 className="font-black text-3xl text-slate-800">ยืนยันยอดชำระ</h3>
                  <div className="bg-slate-50 py-10 rounded-[3.5rem] border border-slate-100">
                    <h1 className="text-7xl font-black text-slate-900 tracking-tighter">{storeConfig.currency}{total.toFixed(2)}</h1>
                  </div>
                  <div className="grid grid-cols-3 gap-4">
                    {['cash', 'promptpay', 'transfer'].map(method => (
                      <button 
                        key={method} 
