                      >
                         <span className="text-xs font-black uppercase tracking-widest">{method}</span>
                      </button>
                    ))}
                  </div>
                  <button 
                    onClick={() => finalizeOrder(paymentMethod)} 
                    className="w-full bg-primary-600 text-white py-8 rounded-[3rem] font-black text-3xl shadow-2xl uppercase tracking-widest"
                  >
                    ยืนยัน
