                 <Mic size={48} className="text-white" />
              </div>
              <div className="text-center space-y-2">
                 <h2 className="text-3xl font-black text-slate-900">กำลังฟังคำสั่ง...</h2>
                 <p className="text-slate-500 font-bold italic">"สั่งสินค้า หรือ บอกให้คิดเงินได้เลยครับ"</p>
              </div>

              {/* Real-time Feedback in Overlay */}
              <div className="w-full space-y-4">
                {voiceLastAction && (
                    <div className="bg-emerald-50 border-2 border-emerald-100 p-4 rounded-2xl flex items-center justify-between animate-in slide-in-from-top-4">
                        <div className="flex items-center gap-3">
                            <CheckCircle className="text-emerald-500" />
                            <span className="font-bold text-emerald-800">{voiceLastAction}</span>
                        </div>
                    </div>
