                <div className="bg-slate-50 p-6 rounded-3xl border border-slate-200 text-center">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">ยอดชำระขณะนี้</p>
                    <p className="text-5xl font-black text-primary-600 tracking-tighter">{storeConfig.currency}{subtotal.toFixed(2)}</p>
                </div>
              </div>

              <button onClick={stopVoiceSession} className="w-full py-4 bg-red-50 text-red-600 rounded-2xl font-black text-lg hover:bg-red-100 transition-all active:scale-95 shadow-lg border-2 border-red-100">ปิดไมค์สั่งงาน</button>
           </div>
