            </div>
            <button onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} className={`px-6 py-2 rounded-xl flex items-center gap-3 font-black text-base border-2 transition-all shadow-md active:scale-95 ${isVoiceActive ? 'border-primary-500 bg-primary-50 text-primary-600' : 'border-slate-200 bg-white text-slate-700 hover:border-primary-200'}`}>
                {isVoiceActive ? <MicOff size={22} /> : <Sparkles size={20} className="text-primary-500" />}
                <span>{isVoiceActive ? 'ปิดไมค์' : 'ใช้คำสั่งเสียง'}</span>
            </button>
          </div>
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {['ทั้งหมด', ...new Set(products.map(p => p.category))].map(cat => (
              <button key={cat} onClick={() => setSelectedCategory(cat)} className={`px-5 py-2 rounded-full text-sm font-bold transition-all shadow-sm border ${selectedCategory === cat ? 'bg-primary-600 text-white border-primary-600 shadow-primary-100' : 'bg-white text-slate-500 border-slate-100 hover:bg-slate-50'}`}>{cat}</button>
            ))}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
