                  <span className={`text-[10px] px-2 py-0.5 rounded-full font-black uppercase ${product.stock < storeConfig.lowStockThreshold ? 'bg-red-50 text-red-600' : 'bg-slate-100 text-slate-400'}`}>คลัง {product.stock}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Right Cart Sidebar */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-6 border-b border-slate-100 flex justify-between bg-slate-50/40">
            <h2 className="font-black text-2xl text-slate-800 flex items-center gap-3"><ShoppingCart size={28} className="text-primary-600"/> ตะกร้า</h2>
            <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:text-red-600 px-4 py-2 bg-red-50 rounded-full transition-all uppercase tracking-widest">ล้าง</button>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {cart.map(item => (
            <div key={item.id} className="flex gap-4 bg-white p-5 rounded-[2.2rem] border border-slate-50 shadow-sm hover:shadow-md transition-all">
              <img src={item.image} className="w-16 h-16 rounded-3xl object-cover border border-slate-100 shadow-sm" />
              <div className="flex-1 min-w-0">
                <h4 className="text-sm font-black text-slate-800 truncate">{item.name}</h4>
                <div className="text-primary-600 font-black text-lg">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
              </div>
              <div className="flex items-center bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden">
                  <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-white transition-colors"><Minus size={14}/></button>
                  <span className="w-8 text-center text-sm font-black">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-white transition-colors"><Plus size={14}/></button>
              </div>
            </div>
          ))}
        </div>
        <div className="p-8 bg-slate-900 text-white rounded-t-[4rem] shadow-2xl">
          <div className="flex justify-between text-4xl font-black mb-8 tracking-tighter"><span>สุทธิ</span><span>{storeConfig.currency}{total.toFixed(2)}</span></div>
          <button onClick={() => setIsCheckoutOpen(true)} disabled={cart.length === 0} className="w-full bg-primary-500 hover:bg-primary-400 disabled:bg-slate-800 disabled:text-slate-600 text-white py-6 rounded-[2.5rem] font-black text-2xl shadow-2xl transition-all active:scale-[0.98] flex items-center justify-center gap-4 uppercase tracking-widest">
            <Banknote size={32} /> ชำระเงิน
          </button>
        </div>
      </div>

      {/* Manual Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-[4rem] shadow-2xl overflow-hidden flex flex-col md:flex-row animate-in zoom-in-95 duration-300">
            <div className="flex-1 p-10 border-r border-slate-100 text-center">
              {completedOrder ? (
                <div className="space-y-10 animate-in fade-in">
                  <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce shadow-xl mx-auto"><CheckCircle size={80} /></div>
                  <h2 className="text-5xl font-black text-slate-900 tracking-tight">สำเร็จ!</h2>
                  <div className="bg-slate-50 rounded-[3rem] p-10 border border-slate-100 shadow-inner">
                     <p className="text-slate-500 font-black text-sm uppercase tracking-[0.3em] mb-3">เงินทอน</p>
                     <span className="font-black text-emerald-600 text-7xl tracking-tighter">{storeConfig.currency}{completedOrder.change?.toFixed(2)}</span>
                  </div>
                  <button onClick={() => {setIsCheckoutOpen(false); setCompletedOrder(null);}} className="w-full bg-slate-900 text-white py-8 rounded-[2.8rem] font-black text-2xl shadow-2xl transition-all uppercase tracking-widest">บิลใหม่</button>
                </div>
              ) : (
                <div className="space-y-8">
                  <h3 className="font-black text-3xl text-slate-800">สรุปการชำระ</h3>
                  <div className="bg-slate-50 py-10 rounded-[3.5rem] border border-slate-100 shadow-inner">
                    <h1 className="text-7xl font-black text-slate-900 tracking-tighter">{storeConfig.currency}{total.toFixed(2)}</h1>
                  </div>
                  <div className="grid grid-cols-3 gap-4">
                    {['cash', 'promptpay', 'transfer'].map(method => (
                      <button 
                        key={method} 
                        onClick={() => setPaymentMethod(method as PaymentMethodType)}
                        className={`flex flex-col items-center justify-center p-6 rounded-[2.5rem] border-4 transition-all gap-3 ${paymentMethod === method ? 'border-primary-500 bg-primary-50 text-primary-600 shadow-xl' : 'border-slate-50 bg-white hover:border-slate-200 text-slate-500'}`}
                      >
                        <span className="text-xs font-black uppercase tracking-widest">{method === 'cash' ? 'เงินสด' : method === 'promptpay' ? 'พร้อมเพย์' : 'โอนเงิน'}</span>
                      </button>
                    ))}
                  </div>
                  <button onClick={() => finalizeOrder(paymentMethod)} className="w-full bg-primary-600 text-white py-8 rounded-[3rem] font-black text-3xl shadow-2xl transition-all active:scale-[0.98] uppercase tracking-widest">ยืนยัน</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info, Sparkles } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Helpers ---
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, coupons, members, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  // Sync cart to ref for AI
  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ทั้งหมด');

  // Checkout Modal State
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [amountPaid, setAmountPaid] = useState<string>('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // Voice Command States
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [voiceLastItem, setVoiceLastItem] = useState<string | null>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);

  // --- Cart Management ---
  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
    setVoiceLastItem(`${product.name} (${quantity} ชิ้น)`);
    setTimeout(() => setVoiceLastItem(null), 4000);
  }, []);

  const updateQuantity = useCallback((id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        if (newQty > item.stock && delta > 0) return item;
        return { ...item, quantity: Math.max(0, newQty) };
      }
      return item;
    }).filter(item => item.quantity > 0));
  }, []);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);
  const total = subtotal; 
  const changeAmt = paymentMethod === 'cash' ? Math.max(0, parseFloat(amountPaid || '0') - total) : 0;

  // --- Order Finalization ---
  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const finalCart = cartRef.current;
    if (finalCart.length === 0) return { total: 0, received: 0, change: 0 };

    const finalSubtotal = finalCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const received = pReceived !== undefined ? pReceived : (pMethod === 'cash' ? parseFloat(amountPaid || '0') : finalSubtotal);
    const finalChange = pMethod === 'cash' ? Math.max(0, received - finalSubtotal) : 0;

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...finalCart],
      subtotal: finalSubtotal,
      discount: 0,
      discountType: 'amount',
      total: finalSubtotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total: finalSubtotal, received, change: finalChange };
  }, [addOrder, orders.length, storeConfig.queueEnabled, amountPaid]);

  // --- Robust Voice Session Management ---
  const stopVoiceSession = useCallback(async () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    // Explicitly close audio contexts to free microphone hardware
    if (inputContextRef.current) {
      try { await inputContextRef.current.close(); } catch(e) {}
      inputContextRef.current = null;
    }

    setIsVoiceActive(false);
    setVoiceLastItem(null);

    // Give hardware time to release before restarting wake-word
    setTimeout(() => {
      if (recognitionRef.current && !isVoiceActive) {
        try { recognitionRef.current.start(); } catch (e) {}
      }
    }, 1000);
  }, [isVoiceActive]);

  const startVoiceSession = async () => {
    if (isVoiceActive) return;

    // 1. Kill background recognition immediately
    if (recognitionRef.current) {
      try { recognitionRef.current.stop(); } catch (e) {}
    }

    setIsVoiceActive(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // 2. Fresh Audio Setup
    if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const outCtx = audioContextRef.current;
    const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    inputContextRef.current = inCtx;

    const addToCartTool: FunctionDeclaration = {
      name: 'addToCartByName',
      parameters: {
        type: Type.OBJECT,
        description: 'ค้นหาและเพิ่มสินค้าลงตะกร้า',
        properties: {
          productName: { type: Type.STRING, description: 'ชื่อสินค้า' },
          quantity: { type: Type.NUMBER, description: 'จำนวน' }
        },
        required: ['productName', 'quantity']
      }
    };

    const checkoutTool: FunctionDeclaration = {
      name: 'processVoiceCheckout',
      parameters: {
        type: Type.OBJECT,
        description: 'ชำระเงินและสรุปผลการขาย',
        properties: {
          cashReceived: { type: Type.NUMBER, description: 'จำนวนเงินสดที่รับมา' },
          paymentMethod: { type: Type.STRING, enum: ['cash', 'promptpay', 'transfer'] }
        },
        required: ['paymentMethod']
      }
    };

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
            if (!inputContextRef.current) return;
            const source = inCtx.createMediaStreamSource(stream);
            const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isVoiceActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(s => s.sendRealtimeInput({
                media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
              })).catch(() => {});
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inCtx.destination);
          }).catch(stopVoiceSession);
        },
        onmessage: async (message: LiveServerMessage) => {
          if (message.toolCall) {
            for (const fc of message.toolCall.functionCalls) {
              if (fc.name === 'addToCartByName') {
                const { productName, quantity } = fc.args as any;
                const found = products.find(p => p.name.toLowerCase().includes(productName.toLowerCase()));
                if (found) {
                  addToCart(found, quantity);
                  const currentTotal = cartRef.current.reduce((sum, i) => sum + (i.price * i.quantity), 0);
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `เพิ่ม ${found.name} ${quantity} ชิ้นเรียบร้อย ยอดรวมตอนนี้คือ ${currentTotal.toFixed(2)} บาทครับ` } }
                  }));
                } else {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `ขออภัยครับ ไม่พบสินค้าที่ชื่อ ${productName}` } }
                  }));
                }
              } else if (fc.name === 'processVoiceCheckout') {
                const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                setPaymentMethod(pMethod);
                const res = finalizeOrder(pMethod, cashReceived);
                let text = `ชำระเงินผ่าน ${pMethod} เรียบร้อย ยอดชำระ ${res.total.toFixed(2)} บาท`;
                if (pMethod === 'cash') text += ` รับเงินมา ${res.received.toFixed(2)} บาท คืนเงินทอน ${res.change.toFixed(2)} บาท ขอบคุณครับ`;

                sessionPromise.then(s => s.sendToolResponse({
                  functionResponses: { id: fc.id, name: fc.name, response: { result: text } }
                }));
                // Auto-close mic after AI summarizes the transaction
                setTimeout(stopVoiceSession, 4500);
              }
            }
          }
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (base64Audio && outCtx.state !== 'closed') {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
            const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
            const source = outCtx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outCtx.destination);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
          }
        },
        onclose: stopVoiceSession,
        onerror: stopVoiceSession
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
        systemInstruction: `คุณคือพนักงานขายอัจฉริยะ DBS POS (เพศชาย พูดสุภาพ ลงท้ายด้วยครับ)
        1. เมื่อสั่งสินค้า: ใช้ addToCartByName และบอกยอดเงินรวมปัจจุบันให้ลูกค้าทราบ
        2. เมื่อจ่ายเงิน: ใช้ processVoiceCheckout รองรับ เงินสด, พร้อมเพย์, โอนเงิน
        3. สรุปเงินทอนและขอบคุณลูกค้าเสมอ และแจ้งลูกค้าว่าจะปิดระบบคำสั่งเสียง`,
        tools: [{ functionDeclarations: [addToCartTool, checkoutTool] }]
      }
    });
    sessionRef.current = await sessionPromise;
  };

  // --- Background Wake-word Listener ---
  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true;
    recognition.lang = 'th-TH';
    recognition.interimResults = false;

    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActive) {
        startVoiceSession();
      }
    };

    recognition.onend = () => {
      if (!isVoiceActive) {
        try { recognition.start(); } catch (err) {}
      }
    };

    try { recognition.start(); } catch (e) {}
    recognitionRef.current = recognition;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, [isVoiceActive]);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">

      {/* Voice Mode Visual Overlay */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-2xl z-[100] flex flex-col items-center justify-center animate-in fade-in duration-500">
           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 animate-in zoom-in-95 w-full max-w-xl mx-4 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-primary-400 via-primary-600 to-primary-400 animate-pulse"></div>

              <div className="flex flex-col items-center">
                <div className="w-28 h-28 bg-primary-600 rounded-full flex items-center justify-center animate-pulse shadow-2xl shadow-primary-500/50 mb-6">
                    <Mic size={56} className="text-white" />
                </div>
                <div className="text-center space-y-2">
