                    <p className="text-slate-500 font-bold text-xl italic italic">"สั่งสินค้า หรือ บอกให้คิดเงินได้เลยครับ"</p>
                </div>
              </div>

              {/* Status Section: Items & Total */}
              <div className="w-full space-y-5">
                {voiceLastItem && (
                    <div className="bg-emerald-50 border-2 border-emerald-100 p-5 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4 duration-500">
                        <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center">
                            <CheckCircle size={28} />
                        </div>
                        <div className="flex-1">
                            <p className="text-xs font-black text-emerald-600 uppercase tracking-widest mb-0.5">เพิ่มเข้าตะกร้าแล้ว</p>
