           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 animate-in zoom-in-95 w-full max-w-xl mx-4 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-primary-400 via-primary-600 to-primary-400 animate-pulse"></div>

              <div className="flex flex-col items-center">
                <div className="w-28 h-28 bg-primary-600 rounded-full flex items-center justify-center animate-pulse shadow-2xl shadow-primary-500/50 mb-6">
                    <Mic size={56} className="text-white" />
                </div>
                <div className="text-center space-y-2">
                    <h2 className="text-4xl font-black text-slate-900 tracking-tight">กำลังฟังคำสั่ง...</h2>
                    <p className="text-slate-500 font-bold text-xl italic">"สั่งสินค้า หรือ บอกให้คิดเงินได้เลยครับ"</p>
                </div>
              </div>

              {/* Real-time Status Area */}
              <div className="w-full space-y-5">
                {voiceLastAction && (
                    <div className="bg-emerald-50 border-2 border-emerald-100 p-5 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4 duration-500">
                        <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center">
                            <CheckCircle size={28} />
                        </div>
                        <div className="flex-1">
                            <p className="text-xs font-black text-emerald-600 uppercase tracking-widest mb-0.5">สถานะล่าสุด</p>
                            <p className="text-xl font-black text-emerald-900">{voiceLastAction}</p>
                        </div>
                    </div>
                )}

                <div className="bg-slate-50 p-8 rounded-[3rem] border border-slate-200 text-center shadow-inner">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-[0.3em] mb-2">ยอดชำระเงินรวมขณะนี้</p>
                    <p className="text-7xl font-black text-primary-600 tracking-tighter">
                        <span className="text-4xl mr-1">{storeConfig.currency}</span>
                        {subtotal.toFixed(2)}
                    </p>
                </div>
              </div>

              <div className="w-full space-y-3">
                 <button 
                  onClick={stopVoiceSession} 
                  className="w-full py-6 bg-red-50 text-red-600 rounded-[2.5rem] font-black text-2xl hover:bg-red-100 transition-all active:scale-95 shadow-lg border-2 border-red-100 flex items-center justify-center gap-4"
                >
                  <MicOff size={32}/> ปิดไมค์สั่งงาน
                </button>
                <p className="text-[10px] text-slate-400 text-center uppercase font-black tracking-widest">หรือพูดว่า "ปิดไมค์"</p>
              </div>
           </div>
        </div>
      )}

      {/* Main UI (Product Grid) */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10 border-b border-slate-100">
          <div className="flex flex-col sm:flex-row gap-3 mb-4">
