                  className={`px-6 py-2 rounded-xl flex items-center gap-3 font-black text-base border-2 transition-all shadow-md active:scale-95 ${isVoiceActive ? 'border-primary-500 bg-primary-50 text-primary-600' : 'border-slate-200 bg-white text-slate-700 hover:border-primary-200'}`}
                >
