                  <button onClick={() => {setIsCheckoutOpen(false); setCompletedOrder(null);}} className="w-full bg-slate-900 text-white py-8 rounded-[2.8rem] font-black text-2xl shadow-2xl transition-all uppercase tracking-widest active:scale-95">รายการถัดไป</button>
                </div>
              ) : (
                <div className="space-y-8">
                  <h3 className="font-black text-3xl text-slate-800 tracking-tight">ยืนยันยอดชำระ</h3>
