import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info, Sparkles } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Helpers ---
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, coupons, members, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  // Sync cart to ref for AI
  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('ทั้งหมด');
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [amountPaid, setAmountPaid] = useState<string>('');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // Voice States
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [voiceLastAction, setVoiceLastAction] = useState<string | null>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);

  // --- Cart Management ---
  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
    setVoiceLastAction(`เพิ่ม ${product.name} x${quantity}`);
    setTimeout(() => setVoiceLastAction(null), 4000);
  }, []);

  const updateQuantity = useCallback((id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        if (newQty > item.stock && delta > 0) return item;
        return { ...item, quantity: Math.max(0, newQty) };
      }
      return item;
    }).filter(item => item.quantity > 0));
  }, []);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);
  const total = subtotal;

  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const finalCart = cartRef.current;
    if (finalCart.length === 0) return { total: 0, received: 0, change: 0 };
    const finalSubtotal = finalCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const received = pReceived !== undefined ? pReceived : (pMethod === 'cash' ? parseFloat(amountPaid || '0') : finalSubtotal);
    const finalChange = pMethod === 'cash' ? Math.max(0, received - finalSubtotal) : 0;

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...finalCart],
      subtotal: finalSubtotal,
      discount: 0,
      discountType: 'amount',
      total: finalSubtotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total: finalSubtotal, received, change: finalChange };
  }, [addOrder, orders.length, storeConfig.queueEnabled, amountPaid]);

  // --- Voice Engine ---
  const stopVoiceSession = useCallback(async () => {
    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }
    if (inputContextRef.current) {
      try { await inputContextRef.current.close(); } catch(e) {}
      inputContextRef.current = null;
    }
    setIsVoiceActive(false);
    setVoiceLastAction(null);
    setTimeout(() => {
      if (recognitionRef.current) try { recognitionRef.current.start(); } catch (e) {}
    }, 1000);
  }, []);

  const startVoiceSession = async () => {
    if (isVoiceActive) return;
    if (recognitionRef.current) try { recognitionRef.current.stop(); } catch (e) {}
    setIsVoiceActive(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Fresh Audio
    if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const outCtx = audioContextRef.current;
    const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    inputContextRef.current = inCtx;

    // Define Tools
    const addToCartTool: FunctionDeclaration = {
      name: 'addToCartByName',
      parameters: {
        type: Type.OBJECT,
        description: 'เพิ่มสินค้าเข้าตะกร้าโดยค้นหาจากชื่อ',
        properties: {
          productName: { type: Type.STRING, description: 'ชื่อสินค้าที่ลูกค้าต้องการ' },
          quantity: { type: Type.NUMBER, description: 'จำนวนชิ้น' }
        },
        required: ['productName', 'quantity']
      }
    };

    const checkoutTool: FunctionDeclaration = {
      name: 'processCheckout',
      parameters: {
        type: Type.OBJECT,
        description: 'ดำเนินการชำระเงิน',
        properties: {
          cashReceived: { type: Type.NUMBER, description: 'เงินสดที่รับมา (ถ้ามี)' },
          paymentMethod: { type: Type.STRING, enum: ['cash', 'promptpay', 'transfer'] }
        },
        required: ['paymentMethod']
      }
    };

    // Build Product List for AI Context
    const productListString = products.map(p => `- ${p.name} (ราคา ${p.price}, สต็อก ${p.stock})`).join('\n');

    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
            if (!inputContextRef.current) return;
            const source = inCtx.createMediaStreamSource(stream);
            const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              if (!isVoiceActive) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              sessionPromise.then(s => s.sendRealtimeInput({
                media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
              })).catch(() => {});
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inCtx.destination);
          }).catch(stopVoiceSession);
        },
        onmessage: async (message: LiveServerMessage) => {
          if (message.toolCall) {
            for (const fc of message.toolCall.functionCalls) {
              if (fc.name === 'addToCartByName') {
                const { productName, quantity } = fc.args as any;
                // Fuzzy Search
                const found = products.find(p => p.name.toLowerCase().includes(productName.toLowerCase()) || productName.toLowerCase().includes(p.name.toLowerCase()));

                if (found) {
                  addToCart(found, quantity);
                  const currentTotal = cartRef.current.reduce((sum, i) => sum + (i.price * i.quantity), 0);
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `เพิ่ม ${found.name} ${quantity} ชิ้น สำเร็จ! ยอดรวมตอนนี้คือ ${currentTotal.toFixed(2)} บาทครับ` } }
                  }));
                } else {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `ขอโทษครับ ผมไม่พบสินค้าชื่อ "${productName}" ในรายการ` } }
                  }));
                }
              } else if (fc.name === 'processCheckout') {
                const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                setPaymentMethod(pMethod);
                const res = finalizeOrder(pMethod, cashReceived);
                let msg = `ชำระเงินเรียบร้อย ยอดรวม ${res.total.toFixed(2)} บาท`;
                if (pMethod === 'cash') msg += ` รับมา ${res.received.toFixed(2)} บาท ทอนเงิน ${res.change.toFixed(2)} บาท ขอบคุณครับ`;

                sessionPromise.then(s => s.sendToolResponse({
                  functionResponses: { id: fc.id, name: fc.name, response: { result: msg } }
                }));
                setTimeout(stopVoiceSession, 5000);
              }
            }
          }
          const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
          if (base64Audio && outCtx.state !== 'closed') {
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
            const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
            const source = outCtx.createBufferSource();
            source.buffer = audioBuffer;
            source.connect(outCtx.destination);
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += audioBuffer.duration;
          }
        },
        onclose: stopVoiceSession,
        onerror: stopVoiceSession
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
        systemInstruction: `คุณคือ "พนักงานขาย DBS POS" (เพศชาย พูดจาสุภาพ ลงท้ายด้วยครับ)

        กฎการทำงานที่สำคัญ:
        1. เมื่อลูกค้าบอกชื่อสินค้าหรือสั่งของ: คุณ **ต้อง** ใช้เครื่องมือ 'addToCartByName' ทันที ห้ามตอบปากเปล่าโดยไม่เรียกใช้เครื่องมือ
        2. รายชื่อสินค้าที่มีในร้าน:
        ${productListString}

        3. หากลูกค้าสั่งสินค้าที่ไม่มีในรายการข้างต้น: ให้แจ้งสุภาพว่าไม่มีสินค้านั้น
        4. เมื่อลูกค้าสั่งคิดเงิน: ใช้เครื่องมือ 'processCheckout' สรุปยอดเงินและเงินทอนให้ชัดเจน
        5. เมื่อจบรายการหรือลูกค้าสั่งปิด: ให้กล่าวขอบคุณและแจ้งว่าจะปิดไมค์`,
        tools: [{ functionDeclarations: [addToCartTool, checkoutTool] }]
      }
    });
    sessionRef.current = await sessionPromise;
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const rec = new (window as any).webkitSpeechRecognition();
    rec.continuous = true;
    rec.lang = 'th-TH';
    rec.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActive) startVoiceSession();
      if (text.includes("ปิดไมค์") && isVoiceActive) stopVoiceSession();
    };
    rec.onend = () => { if (!isVoiceActive) try { rec.start(); } catch (err) {} };
    try { rec.start(); } catch (e) {}
    recognitionRef.current = rec;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, [isVoiceActive]);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">

      {/* Voice Overlay */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-2xl z-[100] flex flex-col items-center justify-center animate-in fade-in">
           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 w-full max-w-xl mx-4 relative overflow-hidden">
              <div className="w-28 h-28 bg-primary-600 rounded-full flex items-center justify-center animate-pulse shadow-2xl shadow-primary-500/50">
                  <Mic size={56} className="text-white" />
              </div>
              <div className="text-center space-y-2">
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight">ระบบสั่งการด้วยเสียง</h2>
                  <p className="text-slate-500 font-bold text-xl italic italic">"สั่งสินค้าที่ต้องการได้เลยครับ"</p>
              </div>

              <div className="w-full space-y-5">
                {voiceLastAction && (
                    <div className="bg-emerald-50 border-2 border-emerald-100 p-5 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4 duration-500">
                        <CheckCircle className="text-emerald-500" size={32} />
                        <p className="text-xl font-black text-emerald-900">{voiceLastAction}</p>
                    </div>
                )}
                <div className="bg-slate-50 p-8 rounded-[3rem] border border-slate-200 text-center shadow-inner">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-[0.3em] mb-2">ยอดชำระเงินขณะนี้</p>
                    <p className="text-7xl font-black text-primary-600 tracking-tighter">
                        <span className="text-4xl mr-1">{storeConfig.currency}</span>
                        {subtotal.toFixed(2)}
                    </p>
                </div>
              </div>

              <button onClick={stopVoiceSession} className="w-full py-6 bg-red-50 text-red-600 rounded-[2.5rem] font-black text-2xl hover:bg-red-100 transition-all flex items-center justify-center gap-4">
                <MicOff size={32}/> ปิดไมค์
              </button>
           </div>
        </div>
      )}

      {/* Main UI */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10 border-b border-slate-100 flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input type="text" placeholder="ค้นหาสินค้า..." className="w-full pl-10 pr-4 py-3 border rounded-xl border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none text-lg" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} />
          </div>
          <button onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} className={`px-6 py-2 rounded-xl flex items-center gap-3 font-black text-base border-2 transition-all shadow-md active:scale-95 ${isVoiceActive ? 'border-primary-500 bg-primary-50 text-primary-600' : 'border-slate-200 bg-white text-slate-700 hover:border-primary-200'}`}>
             {isVoiceActive ? <MicOff size={22} /> : <Sparkles size={20} className="text-primary-500 animate-pulse" />}
             <span>{isVoiceActive ? 'ปิดไมค์' : 'ใช้คำสั่งเสียง'}</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
          {products.filter(p => p.name.includes(searchQuery)).map(product => (
            <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-start transition-all relative group ${product.stock === 0 ? 'opacity-50 grayscale' : 'hover:shadow-xl hover:border-primary-200 active:scale-95'}`}>
              <img src={product.image} className="w-full aspect-square rounded-3xl mb-4 object-cover shadow-inner group-hover:scale-110 transition-transform duration-700" alt={product.name} />
              <h3 className="font-bold text-slate-800 line-clamp-1 text-base">{product.name}</h3>
              <div className="flex justify-between w-full mt-3 items-center">
                <span className="font-black text-primary-600 text-lg">{storeConfig.currency}{product.price.toFixed(2)}</span>
                <span className={`text-[10px] px-2 py-0.5 rounded-full font-black uppercase ${product.stock < storeConfig.lowStockThreshold ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-500'}`}>เหลือ {product.stock}</span>
              </div>
