                    <h2 className="text-4xl font-black text-slate-900 tracking-tight">กำลังฟังคำสั่ง...</h2>
                    <p className="text-slate-500 font-bold text-xl italic">"สั่งสินค้า หรือ บอกให้คิดเงินได้เลยครับ"</p>
                </div>
              </div>

              {/* Live Status Indicators */}
              <div className="w-full space-y-5">
                {voiceLastAction && (
                    <div className="bg-emerald-50 border-2 border-emerald-100 p-5 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4 duration-500">
                        <div className="w-12 h-12 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center">
                            <CheckCircle size={28} />
