                </div>
              ) : (
                <div className="space-y-6">
                  <h3 className="font-black text-2xl text-slate-800 tracking-tight">ยืนยันยอดชำระ</h3>
                  <div className="bg-slate-50 py-8 rounded-[2.8rem] border border-slate-100 shadow-inner">
                    <h1 className="text-6xl font-black text-slate-900 tracking-tight">{storeConfig.currency}{total.toFixed(2)}</h1>
                  </div>
                  <div className="grid grid-cols-3 gap-3">
                    {['cash', 'promptpay', 'transfer'].map(method => (
                      <button 
                        key={method} 
                        onClick={() => setPaymentMethod(method as PaymentMethodType)}
                        className={`flex flex-col items-center justify-center p-5 rounded-[1.8rem] border-2 transition-all gap-2 ${paymentMethod === method ? 'border-primary-500 bg-primary-50 text-primary-600 shadow-sm' : 'border-slate-50 bg-white hover:border-slate-200 text-slate-500'}`}
                      >
                         <span className="text-[10px] font-black uppercase tracking-wider">{method === 'cash' ? 'เงินสด' : method === 'promptpay' ? 'พร้อมเพย์' : 'โอนเงิน'}</span>
                      </button>
                    ))}
                  </div>
                  <button onClick={() => finalizeOrder(paymentMethod)} className="w-full bg-primary-600 text-white py-6 rounded-[2.2rem] font-black text-2xl shadow-xl transition-all active:scale-[0.98] uppercase tracking-widest">ยืนยันการชำระ</button>
                  <button onClick={() => setIsCheckoutOpen(false)} className="text-slate-400 font-bold hover:text-slate-600">ยกเลิก</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

