import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info, Sparkles } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Helpers ---
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [voiceLastAction, setVoiceLastAction] = useState<string | null>(null);

  const isTransitioningRef = useRef(false);
  const isVoiceActiveRef = useRef(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);

  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
    setVoiceLastAction(`เพิ่ม ${product.name} x${quantity}`);
    setTimeout(() => setVoiceLastAction(null), 4000);
  }, []);

  const updateQuantity = useCallback((id: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === id);
      if (!existing) return prev;
      const newQuantity = existing.quantity + delta;
      if (newQuantity <= 0) return prev.filter(item => item.id !== id);
      if (newQuantity > existing.stock) return prev;
      return prev.map(item => item.id === id ? { ...item, quantity: newQuantity } : item);
    });
  }, []);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);

  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const currentCart = cartRef.current;
    if (currentCart.length === 0) return { total: 0, received: 0, change: 0 };
    const finalSubtotal = currentCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const received = pReceived !== undefined ? pReceived : finalSubtotal;
    const finalChange = Math.max(0, received - finalSubtotal);

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...currentCart],
      subtotal: finalSubtotal,
      discount: 0,
      discountType: 'amount',
      total: finalSubtotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total: finalSubtotal, received, change: finalChange };
  }, [addOrder, orders.length, storeConfig.queueEnabled]);

  const stopVoiceSession = useCallback(async () => {
    if (isTransitioningRef.current) return;

    console.log("POS: Stopping Voice Session...");
    isVoiceActiveRef.current = false;
    setIsVoiceActive(false);

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    if (inputContextRef.current) {
      try { await inputContextRef.current.close(); } catch(e) {}
      inputContextRef.current = null;
    }

    setVoiceLastAction(null);

    // Restart wake-word recognition
    setTimeout(() => {
      if (recognitionRef.current && !isVoiceActiveRef.current) {
        try { recognitionRef.current.start(); } catch (e) {
          console.warn("Recognition restart ignored", e);
        }
      }
    }, 1000);
  }, []);

  const startVoiceSession = async () => {
    if (isVoiceActiveRef.current || isTransitioningRef.current) return;

    isTransitioningRef.current = true;
    console.log("POS: Initiating Voice Session...");

    // 1. Kill background recognition first
    if (recognitionRef.current) {
      try { recognitionRef.current.stop(); } catch (e) {}
    }

    // Hardware release delay
    await new Promise(r => setTimeout(r, 500));

    isVoiceActiveRef.current = true;
    setIsVoiceActive(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }
      const outCtx = audioContextRef.current;
      if (outCtx.state === 'suspended') await outCtx.resume();

      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputContextRef.current = inCtx;

      const productNames = products.map(p => `- ${p.name} (ราคา ${p.price})`).join('\n');

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log("POS: Gemini Session Opened");
            navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
              if (!isVoiceActiveRef.current || !inputContextRef.current) {
                stream.getTracks().forEach(t => t.stop());
                return;
              }
              const source = inCtx.createMediaStreamSource(stream);
              const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
              scriptProcessor.onaudioprocess = (e) => {
                if (!isVoiceActiveRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
                sessionPromise.then(s => s.sendRealtimeInput({
                  media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
                })).catch(stopVoiceSession);
              };
              source.connect(scriptProcessor);
              scriptProcessor.connect(inCtx.destination);
            }).catch(err => {
              console.error("Mic Access Denied", err);
              stopVoiceSession();
            });
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'addToCartByName') {
                  const { productName, quantity } = fc.args as any;
                  const found = products.find(p => p.name.toLowerCase().includes(productName.toLowerCase()) || productName.toLowerCase().includes(p.name.toLowerCase()));
                  if (found) {
                    addToCart(found, quantity);
                    const currentTotal = cartRef.current.reduce((sum, i) => sum + (i.price * i.quantity), 0);
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: `เพิ่ม ${found.name} สำเร็จ ยอดรวมคือ ${currentTotal.toFixed(2)} บาท มีอะไรให้รับเพิ่มอีกไหมครับ?` } }
                    }));
                  } else {
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: `ไม่พบสินค้าชื่อ ${productName} ครับ` } }
                    }));
                  }
                } else if (fc.name === 'processCheckout') {
                  const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                  setPaymentMethod(pMethod);
                  const res = finalizeOrder(pMethod, cashReceived);
                  let reply = `ยอดเงินรวม ${res.total.toFixed(2)} บาท `;
                  if (pMethod === 'cash') reply += `รับเงินมา ${res.received.toFixed(2)} บาท ทอนเงิน ${res.change.toFixed(2)} บาทครับ ขอบคุณครับ หากต้องการสั่งเพิ่มบอกได้นะครับ หรือพูดว่า ปิดไมค์ เพื่อจบการทำงานครับ`;
                  else reply += `ชำระผ่าน ${pMethod} เรียบร้อย ขอบคุณครับ หากมีรายการอื่นแจ้งได้เลยครับ`;

                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: reply } }
                  }));
                  // REMOVED: Auto-stop timeout. Let user decide.
                } else if (fc.name === 'closeMic') {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: "รับทราบครับ ปิดไมโครโฟนเรียบร้อย ขอบคุณที่ใช้บริการครับ" } }
                  }));
                  setTimeout(stopVoiceSession, 2000);
                }
              }
            }
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
            }
          },
          onclose: (e) => {
             console.log("Gemini Session Closed by Server");
             stopVoiceSession();
          },
          onerror: (e) => {
            console.error("Gemini Socket Error", e);
            stopVoiceSession();
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          systemInstruction: `คุณคือพนักงานขาย POS อัจฉริยะ เพศชาย พูดจาสุภาพมาก ลงท้ายด้วยครับเสมอ
          รายการสินค้า:
          ${productNames}

          กฎเหล็ก:
          1. ห้ามปิดการสนทนาเอง เว้นแต่ผู้ใช้จะสั่ง "ปิดไมค์" หรือ "หยุดการทำงาน"
          2. เมื่อเพิ่มสินค้าเสร็จ ให้ถามลูกค้าเสมอว่าต้องการอะไรเพิ่มไหม
          3. เมื่อคิดเงินเสร็จ ให้สรุปยอดและเงินทอน แล้วแสตนด์บายรอคำสั่งต่อไป
          4. หากผู้ใช้สั่ง "ปิดไมค์" ให้เรียกใช้เครื่องมือ closeMic ทันที`,
          tools: [{ functionDeclarations: [
            { name: 'addToCartByName', parameters: { type: Type.OBJECT, properties: { productName: { type: Type.STRING }, quantity: { type: Type.NUMBER } }, required: ['productName', 'quantity'] } },
            { name: 'processCheckout', parameters: { type: Type.OBJECT, properties: { cashReceived: { type: Type.NUMBER }, paymentMethod: { type: Type.STRING, enum: ['cash', 'promptpay', 'transfer'] } }, required: ['paymentMethod'] } },
            { name: 'closeMic', parameters: { type: Type.OBJECT, properties: {} } }
          ] }]
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Failed to start Gemini Session", err);
      stopVoiceSession();
    } finally {
      isTransitioningRef.current = false;
    }
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true;
    recognition.interimResults = false;
    recognition.lang = 'th-TH';

    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim().toLowerCase();
      console.log("Background heard:", text);
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActiveRef.current) {
        startVoiceSession();
      }
    };

    recognition.onend = () => {
      if (!isVoiceActiveRef.current && !isTransitioningRef.current) {
        try { recognition.start(); } catch (err) {}
      }
    };

    try { recognition.start(); } catch (e) {}
    recognitionRef.current = recognition;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, []);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">

      {/* Voice Activity UI Overlay */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-2xl z-[100] flex flex-col items-center justify-center animate-in fade-in duration-500">
           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 animate-in zoom-in-95 w-full max-w-xl mx-4 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1 bg-primary-500 animate-pulse"></div>
              <div className="w-28 h-28 bg-primary-600 rounded-full flex items-center justify-center animate-pulse shadow-2xl shadow-primary-500/50">
                  <Mic size={56} className="text-white" />
              </div>
              <div className="text-center">
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight">ระบบรับคำสั่งเสียงเปิดอยู่</h2>
                  <p className="text-slate-500 font-bold text-xl mt-2 italic">"สั่งเพิ่ม หรือ บอกให้คิดเงินได้ตลอดเวลาครับ"</p>
              </div>

              <div className="w-full space-y-4">
                {voiceLastAction && (
                    <div className="bg-emerald-50 border-2 border-emerald-100 p-5 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4">
                        <CheckCircle size={32} className="text-emerald-500" />
                        <p className="text-xl font-black text-emerald-900">{voiceLastAction}</p>
                    </div>
                )}
                <div className="bg-slate-50 p-8 rounded-[3rem] border border-slate-200 text-center shadow-inner">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-2">ยอดรวมตะกร้าปัจจุบัน</p>
                    <p className="text-7xl font-black text-primary-600 tracking-tighter">
                        <span className="text-4xl mr-1">{storeConfig.currency}</span>
                        {subtotal.toFixed(2)}
                    </p>
                </div>
              </div>

              <div className="w-full flex flex-col gap-3">
                <button onClick={stopVoiceSession} className="w-full py-6 bg-red-50 text-red-600 rounded-[2.5rem] font-black text-2xl hover:bg-red-100 transition-all active:scale-95 shadow-lg border-2 border-red-100 flex items-center justify-center gap-4">
                  <MicOff size={32}/> ปิดไมค์ (Stop)
                </button>
                <p className="text-center text-[11px] font-black text-slate-400 uppercase tracking-widest">หรือพูดว่า "ปิดไมค์"</p>
              </div>
           </div>
        </div>
      )}

      {/* Main POS UI */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10 border-b border-slate-100 flex items-center gap-4">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="text"
                placeholder="ค้นหาสินค้า..."
                className="w-full pl-10 pr-4 py-3 border rounded-xl border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none text-lg transition-all"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <button 
              onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} 
              className={`px-6 py-3 rounded-xl flex items-center gap-3 font-black transition-all shadow-md active:scale-95 border-2 ${isVoiceActive ? 'bg-primary-50 text-primary-600 border-primary-500' : 'bg-white text-slate-700 border-slate-200 hover:border-primary-200'}`}
            >
               {isVoiceActive ? <MicOff size={22} /> : <Sparkles size={20} className="text-primary-500 animate-pulse" />}
               <span>{isVoiceActive ? 'หยุดสั่งงาน' : 'ใช้คำสั่งเสียง'}</span>
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6">
            {products.filter(p => p.name.includes(searchQuery)).map(product => (
              <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-start transition-all group ${product.stock === 0 ? 'opacity-50 grayscale cursor-not-allowed' : 'hover:shadow-xl hover:border-primary-100 active:scale-95'}`}>
                <div className="w-full aspect-square bg-slate-50 rounded-3xl mb-4 overflow-hidden border border-slate-50">
                   <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={product.name} />
                </div>
                <h3 className="font-bold text-slate-800 line-clamp-1 text-sm">{product.name}</h3>
                <div className="flex justify-between w-full mt-2 items-center">
                  <span className="font-black text-primary-600 text-base">{storeConfig.currency}{product.price.toFixed(2)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full font-black uppercase ${product.stock < storeConfig.lowStockThreshold ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>คลัง: {product.stock}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-6 border-b border-slate-100 flex justify-between bg-slate-50/40 items-center">
            <h2 className="font-black text-xl text-slate-800 flex items-center gap-2"><ShoppingCart size={24} className="text-primary-600"/> ตะกร้า</h2>
            <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:text-red-600 px-3 py-1.5 bg-red-50 rounded-full transition-all uppercase tracking-widest">ล้างตะกร้า</button>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {cart.map(item => (
            <div key={item.id} className="flex gap-4 bg-white p-4 rounded-[2rem] border border-slate-50 shadow-sm animate-in slide-in-from-right-4">
              <img src={item.image} className="w-14 h-14 rounded-2xl object-cover border border-slate-100" alt={item.name} />
              <div className="flex-1 min-w-0">
                <h4 className="text-xs font-black text-slate-800 truncate">{item.name}</h4>
                <div className="text-primary-600 font-black text-lg">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
              </div>
              <div className="flex items-center bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">
                  <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-white"><Minus size={14}/></button>
                  <span className="w-8 text-center text-xs font-black">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-white"><Plus size={14}/></button>
              </div>
            </div>
          ))}
        </div>
        <div className="p-8 bg-slate-900 text-white rounded-t-[3.5rem] shadow-2xl">
          <div className="flex justify-between text-3xl font-black mb-8 tracking-tighter">
            <span>สุทธิ</span>
            <span>{storeConfig.currency}{subtotal.toFixed(2)}</span>
          </div>
          <button 
            onClick={() => setIsCheckoutOpen(true)} 
            disabled={cart.length === 0} 
            className="w-full bg-primary-500 hover:bg-primary-400 disabled:bg-slate-800 disabled:text-slate-600 text-white py-6 rounded-[2.2rem] font-black text-2xl shadow-xl transition-all active:scale-[0.98] flex items-center justify-center gap-4 uppercase"
          >
            <Banknote size={30} /> ชำระเงิน
          </button>
        </div>
      </div>

      {/* Checkout Success Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/70 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden p-12 text-center animate-in zoom-in-95">
            {completedOrder ? (
              <div className="space-y-8 animate-in fade-in">
                <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce shadow-lg mx-auto"><CheckCircle size={80} /></div>
                <h2 className="text-5xl font-black text-slate-900 tracking-tight">ชำระสำเร็จ!</h2>
                <div className="bg-slate-50 rounded-[2.5rem] p-10 border border-slate-100 shadow-inner">
                   <p className="text-slate-500 font-black text-sm uppercase tracking-[0.3em] mb-3">เงินทอน</p>
                   <span className="font-black text-emerald-600 text-7xl tracking-tighter">{storeConfig.currency}{completedOrder.change?.toFixed(2)}</span>
                </div>
                <button onClick={() => {setIsCheckoutOpen(false); setCompletedOrder(null);}} className="w-full bg-slate-900 text-white py-8 rounded-[2.5rem] font-black text-2xl shadow-2xl transition-all active:scale-95 uppercase tracking-widest">ทำรายการถัดไป</button>
              </div>
            ) : (
              <div className="space-y-6">
                <h3 className="font-black text-3xl text-slate-800 tracking-tight">ยืนยันยอดชำระ</h3>
                <div className="bg-slate-50 py-10 rounded-[3rem] border border-slate-100 shadow-inner">
                  <h1 className="text-7xl font-black text-slate-900 tracking-tight">{storeConfig.currency}{subtotal.toFixed(2)}</h1>
                </div>
                <div className="grid grid-cols-3 gap-3">
                    {['cash', 'promptpay', 'transfer'].map(method => (
                        <button key={method} onClick={() => setPaymentMethod(method as any)} className={`flex flex-col items-center justify-center p-6 rounded-[2rem] border-4 transition-all gap-2 ${paymentMethod === method ? 'border-primary-500 bg-primary-50 text-primary-600 shadow-xl' : 'border-slate-50 bg-white text-slate-400'}`}>
                            <span className="text-[10px] font-black uppercase tracking-widest">{method === 'cash' ? 'เงินสด' : method === 'promptpay' ? 'พร้อมเพย์' : 'โอนเงิน'}</span>
                        </button>
                    ))}
                </div>
                <button onClick={() => finalizeOrder(paymentMethod)} className="w-full bg-primary-600 text-white py-8 rounded-[2.5rem] font-black text-3xl shadow-2xl transition-all active:scale-[0.98] uppercase tracking-widest">ยืนยันการชำระ</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info, Sparkles } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Helpers ---
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [voiceLastAction, setVoiceLastAction] = useState<string | null>(null);

  const isTransitioningRef = useRef(false);
  const isVoiceActiveRef = useRef(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);

  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
    setVoiceLastAction(`เพิ่ม ${product.name} x${quantity}`);
    setTimeout(() => setVoiceLastAction(null), 5000);
  }, []);

  const updateQuantity = useCallback((id: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === id);
      if (!existing) return prev;
      const newQuantity = existing.quantity + delta;
      if (newQuantity <= 0) return prev.filter(item => item.id !== id);
      if (newQuantity > existing.stock) return prev;
      return prev.map(item => item.id === id ? { ...item, quantity: newQuantity } : item);
    });
  }, []);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);

  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const currentCart = cartRef.current;
    if (currentCart.length === 0) return { total: 0, received: 0, change: 0 };
    const finalSubtotal = currentCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const received = pReceived !== undefined ? pReceived : finalSubtotal;
    const finalChange = Math.max(0, received - finalSubtotal);

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...currentCart],
      subtotal: finalSubtotal,
      discount: 0,
      discountType: 'amount',
      total: finalSubtotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total: finalSubtotal, received, change: finalChange };
  }, [addOrder, orders.length, storeConfig.queueEnabled]);

  const stopVoiceSession = useCallback(async () => {
    if (isTransitioningRef.current) return;

    console.log("POS: Stopping Voice Session...");
    isVoiceActiveRef.current = false;
    setIsVoiceActive(false);

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    if (inputContextRef.current) {
      try { await inputContextRef.current.close(); } catch(e) {}
      inputContextRef.current = null;
    }

    setVoiceLastAction(null);

    setTimeout(() => {
      if (recognitionRef.current && !isVoiceActiveRef.current) {
        try { recognitionRef.current.start(); } catch (e) {}
      }
    }, 1000);
  }, []);

  const startVoiceSession = async () => {
    if (isVoiceActiveRef.current || isTransitioningRef.current) return;

    isTransitioningRef.current = true;
    console.log("POS: Initiating Voice Session...");

    if (recognitionRef.current) {
      try { recognitionRef.current.stop(); } catch (e) {}
    }

    await new Promise(r => setTimeout(r, 500));

    isVoiceActiveRef.current = true;
    setIsVoiceActive(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    try {
      if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }
      const outCtx = audioContextRef.current;
      if (outCtx.state === 'suspended') await outCtx.resume();

      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputContextRef.current = inCtx;

      const productListString = products.map(p => `- ${p.name} (ราคา ${p.price} บาท)`).join('\n');

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log("POS: Gemini Session Opened");
            navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
              if (!isVoiceActiveRef.current || !inputContextRef.current) {
                stream.getTracks().forEach(t => t.stop());
                return;
              }
              const source = inCtx.createMediaStreamSource(stream);
              const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
              scriptProcessor.onaudioprocess = (e) => {
                if (!isVoiceActiveRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
                sessionPromise.then(s => s.sendRealtimeInput({
                  media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
                })).catch(stopVoiceSession);
              };
              source.connect(scriptProcessor);
              scriptProcessor.connect(inCtx.destination);
            }).catch(err => {
              console.error("Mic Access Denied", err);
              stopVoiceSession();
            });
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'addToCartByName') {
                  const { productName, quantity } = fc.args as any;
                  // Improved fuzzy matching logic
                  const found = products.find(p => {
                    const pName = p.name.toLowerCase();
                    const sName = productName.toLowerCase();
                    return pName.includes(sName) || sName.includes(pName);
                  });

                  if (found) {
                    addToCart(found, quantity || 1);
                    const currentTotal = cartRef.current.reduce((sum, i) => sum + (i.price * i.quantity), 0);
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { 
                        id: fc.id, 
                        name: fc.name, 
                        response: { result: `เพิ่ม ${found.name} จำนวน ${quantity || 1} ชิ้นเรียบร้อยครับ ยอดรวมตอนนี้ ${currentTotal.toFixed(2)} บาท รับอะไรเพิ่มอีกไหมครับ?` } 
                      }
                    }));
                  } else {
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: `ไม่พบสินค้าชื่อ "${productName}" ในระบบครับ ลองระบุชื่อให้ชัดเจนขึ้นได้ไหมครับ?` } }
                    }));
                  }
                } else if (fc.name === 'processCheckout') {
                  const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                  setPaymentMethod(pMethod);
                  const res = finalizeOrder(pMethod, cashReceived);
                  let reply = `ยอดเงินรวม ${res.total.toFixed(2)} บาท `;
                  if (pMethod === 'cash') reply += `รับเงินมา ${res.received.toFixed(2)} บาท ทอนเงิน ${res.change.toFixed(2)} บาทครับ ขอบคุณที่ใช้บริการครับ พูดว่า "ปิดไมค์" เพื่อจบการทำงานครับ`;
                  else reply += `ชำระผ่าน ${pMethod} เรียบร้อย ขอบคุณครับ หากต้องการทำรายการอื่นแจ้งได้เลยครับ`;

                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: reply } }
                  }));
                } else if (fc.name === 'closeMic') {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: "ปิดไมโครโฟนเรียบร้อย ขอบคุณครับ" } }
                  }));
                  setTimeout(stopVoiceSession, 1500);
                }
              }
            }
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
            }
          },
          onclose: stopVoiceSession,
          onerror: stopVoiceSession
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          systemInstruction: `คุณคือพนักงานขาย POS อัจฉริยะ (ชาย) สุภาพ ลงท้ายด้วยครับเสมอ
          หน้าที่ของคุณคือฟังลูกค้าและใช้เครื่องมือจัดการสินค้า:

          รายการสินค้าที่มีในร้าน:
          ${productListString}

          กฎการทำงาน:
          1. เมื่อลูกค้าบอกชื่อสินค้า หรือจำนวน (เช่น "เอาคริสตัล 2" หรือ "ขอน้ำเปล่า 1") ให้เรียกใช้เครื่องมือ addToCartByName ทันที ห้ามตอบด้วยคำพูดเพียงอย่างเดียว
          2. หากลูกค้าเรียกชื่อสินค้าไม่ตรงเป๊ะ ให้พยายามหาชื่อที่ใกล้เคียงที่สุดในรายการข้างต้น
          3. หากลูกค้าต้องการ "คิดเงิน" หรือ "ชำระเงิน" ให้เรียกใช้เครื่องมือ processCheckout
          4. หลังจากทำงานสำเร็จ ให้ถามลูกค้าว่า "รับอะไรเพิ่มอีกไหมครับ" หรือ "ต้องการชำระเงินเลยไหมครับ"
          5. หากลูกค้าสั่ง "ปิดไมค์" หรือ "เลิกใช้งาน" ให้เรียกใช้เครื่องมือ closeMic`,
          tools: [{ functionDeclarations: [
            { 
              name: 'addToCartByName', 
              description: 'เพิ่มสินค้าลงตะกร้าโดยระบุชื่อและจำนวน',
              parameters: { 
                type: Type.OBJECT, 
                properties: { 
                  productName: { type: Type.STRING, description: 'ชื่อสินค้าที่ลูกค้าสั่ง' }, 
                  quantity: { type: Type.NUMBER, description: 'จำนวนสินค้า' } 
                }, 
                required: ['productName'] 
              } 
            },
            { 
              name: 'processCheckout', 
              description: 'ดำเนินการคิดเงินและชำระเงิน',
              parameters: { 
                type: Type.OBJECT, 
                properties: { 
                  cashReceived: { type: Type.NUMBER, description: 'เงินสดที่รับมา (เฉพาะกรณีจ่ายเงินสด)' }, 
                  paymentMethod: { type: Type.STRING, enum: ['cash', 'promptpay', 'transfer'], description: 'วิธีชำระเงิน' } 
                }, 
                required: ['paymentMethod'] 
              } 
            },
            { name: 'closeMic', description: 'ปิดระบบสั่งงานด้วยเสียง', parameters: { type: Type.OBJECT, properties: {} } }
          ] }]
        }
      });
      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error("Failed to start Gemini Session", err);
      stopVoiceSession();
    } finally {
      isTransitioningRef.current = false;
    }
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true;
    recognition.lang = 'th-TH';

    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim().toLowerCase();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActiveRef.current) {
        startVoiceSession();
      }
    };

    recognition.onend = () => {
      if (!isVoiceActiveRef.current && !isTransitioningRef.current) {
        try { recognition.start(); } catch (err) {}
      }
    };

    try { recognition.start(); } catch (e) {}
    recognitionRef.current = recognition;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, []);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">

      {/* Voice UI Overlay */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-2xl z-[100] flex flex-col items-center justify-center animate-in fade-in duration-500">
           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 animate-in zoom-in-95 w-full max-w-xl mx-4">
              <div className="w-28 h-28 bg-primary-600 rounded-full flex items-center justify-center animate-pulse shadow-2xl shadow-primary-500/50">
                  <Mic size={56} className="text-white" />
              </div>
              <div className="text-center">
                  <h2 className="text-4xl font-black text-slate-900 tracking-tight">กำลังฟังคำสั่งเสียง...</h2>
                  <p className="text-slate-500 font-bold text-xl mt-2 italic">"บอกชื่อสินค้าและจำนวนได้เลยครับ"</p>
              </div>

              <div className="w-full space-y-4">
                {voiceLastAction && (
                    <div className="bg-emerald-50 border-2 border-emerald-100 p-5 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4">
                        <CheckCircle size={32} className="text-emerald-500" />
                        <p className="text-xl font-black text-emerald-900">{voiceLastAction}</p>
                    </div>
                )}
                <div className="bg-slate-50 p-8 rounded-[3rem] border border-slate-200 text-center shadow-inner">
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-2">ยอดรวมขณะนี้</p>
                    <p className="text-7xl font-black text-primary-600 tracking-tighter">
                        <span className="text-4xl mr-1">{storeConfig.currency}</span>
                        {subtotal.toFixed(2)}
                    </p>
                </div>
              </div>

              <button onClick={stopVoiceSession} className="w-full py-6 bg-red-50 text-red-600 rounded-[2.5rem] font-black text-2xl hover:bg-red-100 transition-all active:scale-95 shadow-lg border-2 border-red-100 flex items-center justify-center gap-4">
                <MicOff size={32}/> ปิดระบบสั่งงาน
              </button>
           </div>
        </div>
      )}

      {/* Product List Section */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10 border-b border-slate-100 flex items-center gap-4">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="text"
                placeholder="ค้นหาชื่อหรือสแกนสินค้า..."
                className="w-full pl-10 pr-4 py-3 border rounded-xl border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none text-lg transition-all"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <button 
              onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} 
              className={`px-6 py-3 rounded-xl flex items-center gap-3 font-black transition-all shadow-md active:scale-95 border-2 ${isVoiceActive ? 'bg-primary-50 text-primary-600 border-primary-500' : 'bg-white text-slate-700 border-slate-200 hover:border-primary-200'}`}
            >
               {isVoiceActive ? <MicOff size={22} /> : <Sparkles size={20} className="text-primary-500 animate-pulse" />}
               <span>{isVoiceActive ? 'หยุดฟัง' : 'สั่งงานด้วยเสียง'}</span>
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6">
            {products.filter(p => p.name.includes(searchQuery)).map(product => (
              <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-start transition-all group ${product.stock === 0 ? 'opacity-50 grayscale cursor-not-allowed' : 'hover:shadow-xl hover:border-primary-100 active:scale-95'}`}>
                <div className="w-full aspect-square bg-slate-50 rounded-3xl mb-4 overflow-hidden border border-slate-50">
                   <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={product.name} />
                </div>
                <h3 className="font-bold text-slate-800 line-clamp-1 text-sm">{product.name}</h3>
                <div className="flex justify-between w-full mt-2 items-center">
                  <span className="font-black text-primary-600 text-base">{storeConfig.currency}{product.price.toFixed(2)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full font-black uppercase ${product.stock < storeConfig.lowStockThreshold ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>สต็อก: {product.stock}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-6 border-b border-slate-100 flex justify-between bg-slate-50/40 items-center">
            <h2 className="font-black text-xl text-slate-800 flex items-center gap-2"><ShoppingCart size={24} className="text-primary-600"/> ตะกร้า</h2>
            <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:text-red-600 px-3 py-1.5 bg-red-50 rounded-full transition-all uppercase tracking-widest">ล้างออก</button>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {cart.map(item => (
            <div key={item.id} className="flex gap-4 bg-white p-4 rounded-[2rem] border border-slate-50 shadow-sm animate-in slide-in-from-right-4">
              <img src={item.image} className="w-14 h-14 rounded-2xl object-cover border border-slate-100" alt={item.name} />
              <div className="flex-1 min-w-0">
                <h4 className="text-xs font-black text-slate-800 truncate">{item.name}</h4>
                <div className="text-primary-600 font-black text-lg">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
              </div>
              <div className="flex items-center bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">
                  <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-white"><Minus size={14}/></button>
                  <span className="w-8 text-center text-xs font-black">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-white"><Plus size={14}/></button>
              </div>
            </div>
          ))}
        </div>
        <div className="p-8 bg-slate-900 text-white rounded-t-[3.5rem] shadow-2xl">
          <div className="flex justify-between text-3xl font-black mb-8 tracking-tighter">
            <span>สุทธิ</span>
            <span>{storeConfig.currency}{subtotal.toFixed(2)}</span>
          </div>
          <button 
            onClick={() => setIsCheckoutOpen(true)} 
            disabled={cart.length === 0} 
            className="w-full bg-primary-500 hover:bg-primary-400 disabled:bg-slate-800 disabled:text-slate-600 text-white py-6 rounded-[2.2rem] font-black text-2xl shadow-xl transition-all active:scale-[0.98] flex items-center justify-center gap-4 uppercase"
          >
            <Banknote size={30} /> ชำระเงิน
          </button>
        </div>
      </div>

      {/* Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/70 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden p-12 text-center animate-in zoom-in-95">
            {completedOrder ? (
              <div className="space-y-8 animate-in fade-in">
                <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce shadow-lg mx-auto"><CheckCircle size={80} /></div>
                <h2 className="text-5xl font-black text-slate-900 tracking-tight">ชำระสำเร็จ!</h2>
                <div className="bg-slate-50 rounded-[2.5rem] p-10 border border-slate-100 shadow-inner">
                   <p className="text-slate-500 font-black text-sm uppercase tracking-[0.3em] mb-3">เงินทอน</p>
                   <span className="font-black text-emerald-600 text-7xl tracking-tighter">{storeConfig.currency}{completedOrder.change?.toFixed(2)}</span>
                </div>
                <button onClick={() => {setIsCheckoutOpen(false); setCompletedOrder(null);}} className="w-full bg-slate-900 text-white py-8 rounded-[2.5rem] font-black text-2xl shadow-2xl transition-all active:scale-95 uppercase tracking-widest">ทำรายการถัดไป</button>
              </div>
            ) : (
              <div className="space-y-6">
                <h3 className="font-black text-3xl text-slate-800 tracking-tight">ยืนยันยอดชำระ</h3>
                <div className="bg-slate-50 py-10 rounded-[3rem] border border-slate-100 shadow-inner">
                  <h1 className="text-7xl font-black text-slate-900 tracking-tight">{storeConfig.currency}{subtotal.toFixed(2)}</h1>
                </div>
                <div className="grid grid-cols-3 gap-3">
                    {['cash', 'promptpay', 'transfer'].map(method => (
                        <button key={method} onClick={() => setPaymentMethod(method as any)} className={`flex flex-col items-center justify-center p-6 rounded-[2rem] border-4 transition-all gap-2 ${paymentMethod === method ? 'border-primary-500 bg-primary-50 text-primary-600 shadow-xl' : 'border-slate-50 bg-white text-slate-400'}`}>
                            <span className="text-[10px] font-black uppercase tracking-widest">{method === 'cash' ? 'เงินสด' : method === 'promptpay' ? 'พร้อมเพย์' : 'โอนเงิน'}</span>
                        </button>
                    ))}
                </div>
                <button onClick={() => finalizeOrder(paymentMethod)} className="w-full bg-primary-600 text-white py-8 rounded-[2.5rem] font-black text-3xl shadow-2xl transition-all active:scale-[0.98] uppercase tracking-widest">ยืนยันการชำระ</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info, Sparkles, Loader2 } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Helpers ---
function decode(base64: string) {
  try {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    console.error("Audio Decode Error", e);
    return new Uint8Array(0);
  }
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // UI States
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [voiceLastAction, setVoiceLastAction] = useState<string | null>(null);

  // Refs for stability
  const isTransitioningRef = useRef(false);
  const isVoiceActiveRef = useRef(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);

  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
    setVoiceLastAction(`เพิ่ม ${product.name} x${quantity}`);
    setTimeout(() => setVoiceLastAction(null), 5000);
  }, []);

  const updateQuantity = useCallback((id: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === id);
      if (!existing) return prev;
      const newQuantity = existing.quantity + delta;
      if (newQuantity <= 0) return prev.filter(item => item.id !== id);
      if (newQuantity > existing.stock) return prev;
      return prev.map(item => item.id === id ? { ...item, quantity: newQuantity } : item);
    });
  }, []);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);

  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const currentCart = cartRef.current;
    if (currentCart.length === 0) return { total: 0, received: 0, change: 0 };
    const finalSubtotal = currentCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const received = pReceived !== undefined ? pReceived : finalSubtotal;
    const finalChange = Math.max(0, received - finalSubtotal);

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...currentCart],
      subtotal: finalSubtotal,
      discount: 0,
      discountType: 'percent' as const,
      total: finalSubtotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total: finalSubtotal, received, change: finalChange };
  }, [addOrder, orders.length, storeConfig.queueEnabled]);

  const stopVoiceSession = useCallback(async () => {
    console.log("POS: Stopping Voice Session...");
    isVoiceActiveRef.current = false;
    setIsVoiceActive(false);
    setIsConnecting(false);
    isTransitioningRef.current = false;

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    if (inputContextRef.current) {
      try { await inputContextRef.current.close(); } catch(e) {}
      inputContextRef.current = null;
    }

    setVoiceLastAction(null);

    // Restart background listener after hardware release
    setTimeout(() => {
      if (recognitionRef.current && !isVoiceActiveRef.current) {
        try { recognitionRef.current.start(); } catch (e) {}
      }
    }, 1000);
  }, []);

  const startVoiceSession = async () => {
    // Prevent multiple clicks/starts
    if (isVoiceActiveRef.current || isTransitioningRef.current) return;

    isTransitioningRef.current = true;
    setIsConnecting(true);
    setIsVoiceActive(true); // Show UI immediately for feedback

    console.log("POS: Starting Voice Session...");

    try {
      // 1. Kill background recognition first
      if (recognitionRef.current) {
        try { recognitionRef.current.stop(); } catch (e) {}
      }

      await new Promise(r => setTimeout(r, 600));

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Setup Output Context
      if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }
      const outCtx = audioContextRef.current;
      if (outCtx.state === 'suspended') await outCtx.resume();

      // Setup Input Context
      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputContextRef.current = inCtx;

      const productListString = products.map(p => `- ${p.name} (ราคา ${p.price} บาท)`).join('\n');

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            console.log("POS: Gemini Socket Opened");
            setIsConnecting(false);

            navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
              if (!isVoiceActiveRef.current || !inputContextRef.current) {
                stream.getTracks().forEach(t => t.stop());
                return;
              }
              const source = inCtx.createMediaStreamSource(stream);
              const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
              scriptProcessor.onaudioprocess = (e) => {
                if (!isVoiceActiveRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
                sessionPromise.then(s => s.sendRealtimeInput({
                  media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
                })).catch(stopVoiceSession);
              };
              source.connect(scriptProcessor);
              scriptProcessor.connect(inCtx.destination);
            }).catch(err => {
              console.error("Mic Error", err);
              stopVoiceSession();
            });
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'addToCartByName') {
                  const { productName, quantity } = fc.args as any;
                  const found = products.find(p => {
                    const pName = p.name.toLowerCase();
                    const sName = productName.toLowerCase();
                    return pName.includes(sName) || sName.includes(pName);
                  });

                  if (found) {
                    addToCart(found, quantity || 1);
                    const currentTotal = cartRef.current.reduce((sum, i) => sum + (i.price * i.quantity), 0);
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { 
                        id: fc.id, 
                        name: fc.name, 
                        response: { result: `เพิ่ม ${found.name} จำนวน ${quantity || 1} ชิ้นเรียบร้อย ยอดรวม ${currentTotal.toFixed(2)} บาท รับอะไรเพิ่มไหมครับ?` } 
                      }
                    }));
                  } else {
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: `ไม่พบสินค้าชื่อ "${productName}" ครับ` } }
                    }));
                  }
                } else if (fc.name === 'processCheckout') {
                  const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                  setPaymentMethod(pMethod);
                  const res = finalizeOrder(pMethod, cashReceived);
                  let reply = `ยอดเงินรวม ${res.total.toFixed(2)} บาท `;
                  if (pMethod === 'cash') reply += `รับเงินมา ${res.received.toFixed(2)} บาท ทอนเงิน ${res.change.toFixed(2)} บาทครับ พูดว่า "ปิดไมค์" เพื่อหยุดครับ`;
                  else reply += `ชำระผ่าน ${pMethod} เรียบร้อยครับ`;

                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: reply } }
                  }));
                } else if (fc.name === 'closeMic') {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: "ปิดไมโครโฟนเรียบร้อย" } }
                  }));
                  setTimeout(stopVoiceSession, 1500);
                }
              }
            }
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outCtx.state !== 'closed') {
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
            }
          },
          onclose: stopVoiceSession,
          onerror: stopVoiceSession
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          systemInstruction: `คุณคือพนักงานขาย POS อัจฉริยะ (ชาย) สุภาพ ลงท้ายด้วยครับเสมอ
          รายการสินค้า:
          ${productListString}

          กฎการทำงาน:
          1. เมื่อลูกค้าบอกชื่อสินค้า ให้เรียกใช้เครื่องมือ addToCartByName ทันที
          2. หากลูกค้าต้องการ "คิดเงิน" ให้เรียกใช้เครื่องมือ processCheckout
          3. ห้ามปิดไมค์เอง ยกเว้นลูกค้าสั่ง "ปิดไมค์" ให้เรียกใช้เครื่องมือ closeMic`,
          tools: [{ functionDeclarations: [
            { name: 'addToCartByName', description: 'เพิ่มสินค้าลงตะกร้า', parameters: { type: Type.OBJECT, properties: { productName: { type: Type.STRING }, quantity: { type: Type.NUMBER } }, required: ['productName'] } },
            { name: 'processCheckout', description: 'คิดเงิน', parameters: { type: Type.OBJECT, properties: { cashReceived: { type: Type.NUMBER }, paymentMethod: { type: Type.STRING, enum: ['cash', 'promptpay', 'transfer'] } }, required: ['paymentMethod'] } },
            { name: 'closeMic', description: 'ปิดไมค์', parameters: { type: Type.OBJECT, properties: {} } }
          ] }]
        }
      });

      isVoiceActiveRef.current = true;
      sessionRef.current = await sessionPromise;

    } catch (err) {
      console.error("Critical Start Error", err);
      stopVoiceSession();
    } finally {
      // Release transitioning state so button can be pressed again
      isTransitioningRef.current = false;
    }
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true;
    recognition.lang = 'th-TH';

    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim().toLowerCase();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActiveRef.current) {
        startVoiceSession();
      }
    };

    recognition.onend = () => {
      if (!isVoiceActiveRef.current && !isTransitioningRef.current) {
        try { recognition.start(); } catch (err) {}
      }
    };

    try { recognition.start(); } catch (e) {}
    recognitionRef.current = recognition;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, []);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">

      {/* Voice UI Overlay */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-2xl z-[100] flex flex-col items-center justify-center animate-in fade-in duration-500">
           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 animate-in zoom-in-95 w-full max-w-xl mx-4 relative">

              {isConnecting ? (
                  <div className="flex flex-col items-center gap-6 py-10">
                     <Loader2 size={80} className="text-primary-500 animate-spin" />
                     <h2 className="text-3xl font-black text-slate-800">กำลังเชื่อมต่อ AI...</h2>
                  </div>
              ) : (
                <>
                  <div className="w-28 h-28 bg-primary-600 rounded-full flex items-center justify-center animate-pulse shadow-2xl shadow-primary-500/50">
                      <Mic size={56} className="text-white" />
                  </div>
                  <div className="text-center">
                      <h2 className="text-4xl font-black text-slate-900 tracking-tight">กำลังฟังคำสั่งเสียง...</h2>
                      <p className="text-slate-500 font-bold text-xl mt-2 italic">"บอกชื่อสินค้าและจำนวนได้เลยครับ"</p>
                  </div>

                  <div className="w-full space-y-4">
                    {voiceLastAction && (
                        <div className="bg-emerald-50 border-2 border-emerald-100 p-5 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4">
                            <CheckCircle size={32} className="text-emerald-500" />
                            <p className="text-xl font-black text-emerald-900">{voiceLastAction}</p>
                        </div>
                    )}
                    <div className="bg-slate-50 p-8 rounded-[3rem] border border-slate-200 text-center shadow-inner">
                        <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-2">ยอดรวมขณะนี้</p>
                        <p className="text-7xl font-black text-primary-600 tracking-tighter">
                            <span className="text-4xl mr-1">{storeConfig.currency}</span>
                            {subtotal.toFixed(2)}
                        </p>
                    </div>
                  </div>

                  <button onClick={stopVoiceSession} className="w-full py-6 bg-red-50 text-red-600 rounded-[2.5rem] font-black text-2xl hover:bg-red-100 transition-all active:scale-95 shadow-lg border-2 border-red-100 flex items-center justify-center gap-4">
                    <MicOff size={32}/> ปิดระบบสั่งงาน
                  </button>
                </>
              )}
           </div>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10 border-b border-slate-100 flex items-center gap-4">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="text"
                placeholder="ค้นหาชื่อหรือสแกนสินค้า..."
                className="w-full pl-10 pr-4 py-3 border rounded-xl border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none text-lg transition-all"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <button 
              disabled={isTransitioningRef.current}
              onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} 
              className={`px-6 py-3 rounded-xl flex items-center gap-3 font-black transition-all shadow-md active:scale-95 border-2 ${isVoiceActive ? 'bg-primary-50 text-primary-600 border-primary-500' : 'bg-white text-slate-700 border-slate-200 hover:border-primary-200'} ${isTransitioningRef.current ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
               {isConnecting ? <Loader2 size={20} className="animate-spin" /> : (isVoiceActive ? <MicOff size={22} /> : <Sparkles size={20} className="text-primary-500 animate-pulse" />)}
               <span>{isVoiceActive ? 'หยุดฟัง' : 'สั่งงานด้วยเสียง'}</span>
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6">
            {products.filter(p => p.name.includes(searchQuery)).map(product => (
              <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-start transition-all group ${product.stock === 0 ? 'opacity-50 grayscale cursor-not-allowed' : 'hover:shadow-xl hover:border-primary-100 active:scale-95'}`}>
                <div className="w-full aspect-square bg-slate-50 rounded-3xl mb-4 overflow-hidden border border-slate-50">
                   <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={product.name} />
                </div>
                <h3 className="font-bold text-slate-800 line-clamp-1 text-sm">{product.name}</h3>
                <div className="flex justify-between w-full mt-2 items-center">
                  <span className="font-black text-primary-600 text-base">{storeConfig.currency}{product.price.toFixed(2)}</span>
                  <span className={`text-[10px] px-2 py-0.5 rounded-full font-black uppercase ${product.stock < storeConfig.lowStockThreshold ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'}`}>สต็อก: {product.stock}</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-6 border-b border-slate-100 flex justify-between bg-slate-50/40 items-center">
            <h2 className="font-black text-xl text-slate-800 flex items-center gap-2"><ShoppingCart size={24} className="text-primary-600"/> ตะกร้า</h2>
            <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:text-red-600 px-3 py-1.5 bg-red-50 rounded-full transition-all uppercase tracking-widest">ล้างออก</button>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {cart.map(item => (
            <div key={item.id} className="flex gap-4 bg-white p-4 rounded-[2rem] border border-slate-50 shadow-sm animate-in slide-in-from-right-4">
              <img src={item.image} className="w-14 h-14 rounded-2xl object-cover border border-slate-100" alt={item.name} />
              <div className="flex-1 min-w-0">
                <h4 className="text-xs font-black text-slate-800 truncate">{item.name}</h4>
                <div className="text-primary-600 font-black text-lg">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
              </div>
              <div className="flex items-center bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">
                  <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-white"><Minus size={14}/></button>
                  <span className="w-8 text-center text-xs font-black">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-white"><Plus size={14}/></button>
              </div>
            </div>
          ))}
        </div>
        <div className="p-8 bg-slate-900 text-white rounded-t-[3.5rem] shadow-2xl">
          <div className="flex justify-between text-3xl font-black mb-8 tracking-tighter">
            <span>สุทธิ</span>
            <span>{storeConfig.currency}{subtotal.toFixed(2)}</span>
          </div>
          <button 
            onClick={() => setIsCheckoutOpen(true)} 
            disabled={cart.length === 0} 
            className="w-full bg-primary-500 hover:bg-primary-400 disabled:bg-slate-800 disabled:text-slate-600 text-white py-6 rounded-[2.2rem] font-black text-2xl shadow-xl transition-all active:scale-[0.98] flex items-center justify-center gap-4 uppercase"
          >
            <Banknote size={30} /> ชำระเงิน
          </button>
        </div>
      </div>

      {/* Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/70 z-50 flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden p-12 text-center animate-in zoom-in-95">
            {completedOrder ? (
              <div className="space-y-8 animate-in fade-in">
                <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce shadow-lg mx-auto"><CheckCircle size={80} /></div>
                <h2 className="text-5xl font-black text-slate-900 tracking-tight">ชำระสำเร็จ!</h2>
                <div className="bg-slate-50 rounded-[2.5rem] p-10 border border-slate-100 shadow-inner">
                   <p className="text-slate-500 font-black text-sm uppercase tracking-[0.3em] mb-3">เงินทอน</p>
                   <span className="font-black text-emerald-600 text-7xl tracking-tighter">{storeConfig.currency}{completedOrder.change?.toFixed(2)}</span>
                </div>
                <button onClick={() => {setIsCheckoutOpen(false); setCompletedOrder(null);}} className="w-full bg-slate-900 text-white py-8 rounded-[2.5rem] font-black text-2xl shadow-2xl transition-all active:scale-95 uppercase tracking-widest">ทำรายการถัดไป</button>
              </div>
            ) : (
              <div className="space-y-6">
                <h3 className="font-black text-3xl text-slate-800 tracking-tight">ยืนยันยอดชำระ</h3>
                <div className="bg-slate-50 py-10 rounded-[3rem] border border-slate-100 shadow-inner">
                  <h1 className="text-7xl font-black text-slate-900 tracking-tight">{storeConfig.currency}{subtotal.toFixed(2)}</h1>
                </div>
                <div className="grid grid-cols-3 gap-3">
                    {['cash', 'promptpay', 'transfer'].map(method => (
                        <button key={method} onClick={() => setPaymentMethod(method as any)} className={`flex flex-col items-center justify-center p-6 rounded-[2rem] border-4 transition-all gap-2 ${paymentMethod === method ? 'border-primary-500 bg-primary-50 text-primary-600 shadow-xl' : 'border-slate-50 bg-white text-slate-400'}`}>
                            <span className="text-[10px] font-black uppercase tracking-widest">{method === 'cash' ? 'เงินสด' : method === 'promptpay' ? 'พร้อมเพย์' : 'โอนเงิน'}</span>
                        </button>
                    ))}
                </div>
                <button onClick={() => finalizeOrder(paymentMethod)} className="w-full bg-primary-600 text-white py-8 rounded-[2.5rem] font-black text-3xl shadow-2xl transition-all active:scale-[0.98] uppercase tracking-widest">ยืนยันการชำระ</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info, Sparkles, Loader2, VolumeX } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Helpers ---
function decode(base64: string) {
  try {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    return new Uint8Array(0);
  }
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // UI States
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTalking, setIsTalking] = useState(false);
  const [voiceLastAction, setVoiceLastAction] = useState<string | null>(null);

  // Refs for stability
  const isTransitioningRef = useRef(false);
  const isVoiceActiveRef = useRef(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const talkingTimeoutRef = useRef<any>(null);

  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
    setVoiceLastAction(`เพิ่ม ${product.name} x${quantity}`);
    setTimeout(() => setVoiceLastAction(null), 5000);
  }, []);

  const updateQuantity = useCallback((id: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === id);
      if (!existing) return prev;
      const newQuantity = existing.quantity + delta;
      if (newQuantity <= 0) return prev.filter(item => item.id !== id);
      if (newQuantity > existing.stock) return prev;
      return prev.map(item => item.id === id ? { ...item, quantity: newQuantity } : item);
    });
  }, []);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);

  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const currentCart = cartRef.current;
    if (currentCart.length === 0) return { total: 0, received: 0, change: 0 };
    const finalSubtotal = currentCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const received = pReceived !== undefined ? pReceived : finalSubtotal;
    const finalChange = Math.max(0, received - finalSubtotal);

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...currentCart],
      subtotal: finalSubtotal,
      discount: 0,
      discountType: 'percent' as const,
      total: finalSubtotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    setIsCheckoutOpen(true);
    return { total: finalSubtotal, received, change: finalChange };
  }, [addOrder, orders.length, storeConfig.queueEnabled]);

  const stopVoiceSession = useCallback(async () => {
    console.log("POS: Stopping Voice Session...");
    isVoiceActiveRef.current = false;
    setIsVoiceActive(false);
    setIsConnecting(false);
    setIsTalking(false);
    isTransitioningRef.current = false;

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    if (inputContextRef.current) {
      try { await inputContextRef.current.close(); } catch(e) {}
      inputContextRef.current = null;
    }

    setVoiceLastAction(null);

    setTimeout(() => {
      if (recognitionRef.current && !isVoiceActiveRef.current) {
        try { recognitionRef.current.start(); } catch (e) {}
      }
    }, 1000);
  }, []);

  const startVoiceSession = async () => {
    if (isVoiceActiveRef.current || isTransitioningRef.current) return;

    isTransitioningRef.current = true;
    setIsConnecting(true);
    setIsVoiceActive(true);

    try {
      if (recognitionRef.current) {
        try { recognitionRef.current.stop(); } catch (e) {}
      }

      await new Promise(r => setTimeout(r, 600));

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }
      const outCtx = audioContextRef.current;
      if (outCtx.state === 'suspended') await outCtx.resume();

      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputContextRef.current = inCtx;

      const productListString = products.map(p => `- ${p.name} (ราคา ${p.price} บาท)`).join('\n');

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsConnecting(false);
            navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
              if (!isVoiceActiveRef.current || !inputContextRef.current) {
                stream.getTracks().forEach(t => t.stop());
                return;
              }
              const source = inCtx.createMediaStreamSource(stream);
              const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
              scriptProcessor.onaudioprocess = (e) => {
                if (!isVoiceActiveRef.current) return;
                const inputData = e.inputBuffer.getChannelData(0);
                const int16 = new Int16Array(inputData.length);
                for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
                sessionPromise.then(s => s.sendRealtimeInput({
                  media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' }
                })).catch(stopVoiceSession);
              };
              source.connect(scriptProcessor);
              scriptProcessor.connect(inCtx.destination);
            }).catch(stopVoiceSession);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Tool Calls
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'addToCartByName') {
                  const { productName, quantity } = fc.args as any;
                  // Improved fuzzy matching
                  const found = products.find(p => {
                    const pName = p.name.toLowerCase();
                    const sName = productName.toLowerCase();
                    return pName.includes(sName) || sName.includes(pName);
                  });

                  if (found) {
                    addToCart(found, quantity || 1);
                    const currentTotal = cartRef.current.reduce((sum, i) => sum + (i.price * i.quantity), 0);
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { 
                        id: fc.id, 
                        name: fc.name, 
                        response: { result: `Success: เพิ่ม ${found.name} จำนวน ${quantity || 1} ชิ้นลงตะกร้าแล้ว ยอดรวมใหม่คือ ${currentTotal.toFixed(2)} บาท กรุณาพูดสรุปรายการและถามว่ารับอะไรเพิ่มไหม` } 
                      }
                    }));
                  } else {
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: `Error: ไม่พบสินค้าชื่อ "${productName}" ในสต็อก กรุณาแจ้งลูกค้าและถามอีกครั้ง` } }
                    }));
                  }
                } else if (fc.name === 'processCheckout') {
                  const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                  setPaymentMethod(pMethod);
                  const res = finalizeOrder(pMethod, cashReceived);
                  let reply = `ยอดเงินรวมทั้งสิ้น ${res.total.toFixed(2)} บาทครับ `;
                  if (pMethod === 'cash') reply += `รับเงินมา ${res.received.toFixed(2)} บาท ทอนเงิน ${res.change.toFixed(2)} บาท ขอบคุณมากครับ! หากต้องการจบการทำงานพูดว่า ปิดไมค์ ครับ`;
                  else reply += `ชำระผ่าน ${pMethod} เรียบร้อยครับ ขอบคุณครับ`;

                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: `Transaction Completed. ${reply}` } }
                  }));
                } else if (fc.name === 'closeMic') {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: "ปิดไมค์เรียบร้อยครับ" } }
                  }));
                  setTimeout(stopVoiceSession, 1500);
                }
              }
            }

            // Handle Audio Output (Speaking back)
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outCtx.state !== 'closed') {
              if (outCtx.state === 'suspended') await outCtx.resume();

              setIsTalking(true);
              if (talkingTimeoutRef.current) clearTimeout(talkingTimeoutRef.current);

              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);

              source.onended = () => {
                // Set small timeout to ensure we don't flicker isTalking off between chunks
                talkingTimeoutRef.current = setTimeout(() => setIsTalking(false), 500);
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
            }
          },
          onclose: stopVoiceSession,
          onerror: stopVoiceSession
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          systemInstruction: `คุณคือพนักงานขาย POS อัจฉริยะ (ชาย) ที่มีความเป็นมิตรและสุภาพมากที่สุด ลงท้ายด้วย "ครับ" เสมอ

          หน้าที่ของคุณ:
          1. ฟังชื่อสินค้าที่ลูกค้าสั่ง แล้วเรียกใช้เครื่องมือ addToCartByName ทันที (ห้ามแค่พูดตอบ)
          2. เมื่อเพิ่มสินค้าเสร็จ ให้พูดสรุปด้วยเสียงของคุณว่า "เพิ่ม [ชื่อสินค้า] เรียบร้อยครับ ยอดรวมตอนนี้ [ยอดรวม] บาท รับอะไรเพิ่มอีกไหมครับ?"
          3. เมื่อลูกค้าจะจ่ายเงิน ให้เรียก processCheckout และแจ้งยอดเงินรวมและเงินทอนด้วยเสียงที่ชัดเจน
          4. หากไม่แน่ใจชื่อสินค้า ให้ถามย้ำอย่างสุภาพ

          รายการสินค้าปัจจุบัน:
          ${productListString}

          ห้ามปิดไมค์เองเด็ดขาดจนกว่าลูกค้าจะสั่ง "ปิดไมค์"`,
          tools: [{ functionDeclarations: [
            { name: 'addToCartByName', description: 'เพิ่มสินค้าลงตะกร้า', parameters: { type: Type.OBJECT, properties: { productName: { type: Type.STRING }, quantity: { type: Type.NUMBER } }, required: ['productName'] } },
            { name: 'processCheckout', description: 'ดำเนินการคิดเงิน', parameters: { type: Type.OBJECT, properties: { cashReceived: { type: Type.NUMBER }, paymentMethod: { type: Type.STRING, enum: ['cash', 'promptpay', 'transfer'] } }, required: ['paymentMethod'] } },
            { name: 'closeMic', description: 'ปิดระบบสั่งงานด้วยเสียง', parameters: { type: Type.OBJECT, properties: {} } }
          ] }]
        }
      });

      isVoiceActiveRef.current = true;
      sessionRef.current = await sessionPromise;

    } catch (err) {
      console.error("Critical Start Error", err);
      stopVoiceSession();
    } finally {
      isTransitioningRef.current = false;
    }
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true;
    recognition.lang = 'th-TH';

    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim().toLowerCase();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActiveRef.current) {
        startVoiceSession();
      }
    };

    recognition.onend = () => {
      if (!isVoiceActiveRef.current && !isTransitioningRef.current) {
        try { recognition.start(); } catch (err) {}
      }
    };

    try { recognition.start(); } catch (e) {}
    recognitionRef.current = recognition;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, []);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">

      {/* Voice UI Overlay */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-3xl z-[100] flex flex-col items-center justify-center animate-in fade-in duration-500">
           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 animate-in zoom-in-95 w-full max-w-xl mx-4 relative overflow-hidden">

              {isConnecting ? (
                  <div className="flex flex-col items-center gap-6 py-10">
                     <Loader2 size={80} className="text-primary-500 animate-spin" />
                     <h2 className="text-3xl font-black text-slate-800">กำลังเชื่อมต่อ AI...</h2>
                  </div>
              ) : (
                <>
                  <div className="relative">
                    <div className={`w-32 h-32 rounded-full flex items-center justify-center transition-all duration-500 ${isTalking ? 'bg-emerald-500 scale-110' : 'bg-primary-600 animate-pulse'} shadow-2xl`}>
                        {isTalking ? <Volume2 size={64} className="text-white" /> : <Mic size={64} className="text-white" />}
                    </div>
                    {isTalking && (
                        <div className="absolute -inset-4 border-4 border-emerald-400 rounded-full animate-ping opacity-30"></div>
                    )}
                  </div>

                  <div className="text-center">
                      <h2 className="text-4xl font-black text-slate-900 tracking-tight">
                        {isTalking ? "AI กำลังพูดกับคุณ..." : "กำลังฟังคำสั่งของคุณ..."}
                      </h2>
                      <p className="text-slate-500 font-bold text-xl mt-2 italic">
                        {isTalking ? "กรุณารอสักครู่ครับ" : '"บอกชื่อสินค้าที่ต้องการได้เลยครับ"'}
                      </p>
                  </div>

                  <div className="w-full space-y-4">
                    {voiceLastAction && (
                        <div className="bg-emerald-50 border-2 border-emerald-100 p-5 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4">
                            <CheckCircle size={32} className="text-emerald-500" />
                            <p className="text-xl font-black text-emerald-900">{voiceLastAction}</p>
                        </div>
                    )}
                    <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-700 text-center shadow-2xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 p-4 opacity-10"><Sparkles size={60} className="text-white" /></div>
                        <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-2">ยอดรวมตะกร้า</p>
                        <p className="text-7xl font-black text-white tracking-tighter">
                            <span className="text-3xl mr-1 text-primary-400">{storeConfig.currency}</span>
                            {subtotal.toFixed(2)}
                        </p>
                    </div>
                  </div>

                  <button onClick={stopVoiceSession} className="w-full py-6 bg-red-50 text-red-600 rounded-[2.5rem] font-black text-2xl hover:bg-red-100 transition-all active:scale-95 shadow-lg border-2 border-red-100 flex items-center justify-center gap-4">
                    <MicOff size={32}/> ปิดระบบสั่งงาน
                  </button>
                </>
              )}
           </div>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm z-10 border-b border-slate-100 flex items-center gap-4">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="text"
                placeholder="ค้นหาชื่อหรือสแกนสินค้า..."
                className="w-full pl-10 pr-4 py-3 border rounded-xl border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none text-lg transition-all"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <button 
              disabled={isTransitioningRef.current}
              onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} 
              className={`px-6 py-3 rounded-xl flex items-center gap-3 font-black transition-all shadow-md active:scale-95 border-2 ${isVoiceActive ? 'bg-primary-50 text-primary-600 border-primary-500' : 'bg-white text-slate-700 border-slate-200 hover:border-primary-200'} ${isTransitioningRef.current ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
               {isConnecting ? <Loader2 size={20} className="animate-spin" /> : (isVoiceActive ? <MicOff size={22} /> : <Sparkles size={20} className="text-primary-500 animate-pulse" />)}
               <span>{isVoiceActive ? 'หยุดฟัง' : 'สั่งงานด้วยเสียง'}</span>
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6">
            {products.filter(p => p.name.includes(searchQuery)).map(product => (
