                  <div className={`w-32 h-32 rounded-full flex items-center justify-center transition-all duration-500 ${isTalking ? 'bg-emerald-500 scale-110 shadow-lg' : 'bg-primary-600 animate-pulse'}`}>
                      {isTalking ? <Volume2 size={64} className="text-white" /> : <Mic size={64} className="text-white" />}
