import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info, Sparkles, Loader2, VolumeX, Delete, Copy } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Helpers ---
function decode(base64: string) {
  try {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    return new Uint8Array(0);
  }
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [cashReceivedStr, setCashReceivedStr] = useState('');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // Voice UI States
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTalking, setIsTalking] = useState(false);
  const [voiceLastAction, setVoiceLastAction] = useState<string | null>(null);
  const [micVolume, setMicVolume] = useState(0);

  // Refs for stability
  const isTransitioningRef = useRef(false);
  const isVoiceActiveRef = useRef(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const talkingTimeoutRef = useRef<any>(null);
  const connectionTimeoutRef = useRef<any>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);

  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
    setVoiceLastAction(`เพิ่ม ${product.name} x${quantity}`);
    setTimeout(() => setVoiceLastAction(null), 5000);
  }, []);

  const updateQuantity = useCallback((id: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === id);
      if (!existing) return prev;
      const newQuantity = existing.quantity + delta;
      if (newQuantity <= 0) return prev.filter(item => item.id !== id);
      if (newQuantity > existing.stock) return prev;
      return prev.map(item => item.id === id ? { ...item, quantity: newQuantity } : item);
    });
  }, []);

  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const currentCart = cartRef.current;
    if (currentCart.length === 0) return { total: 0, received: 0, change: 0 };
    const finalSubtotal = currentCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const received = pReceived !== undefined ? pReceived : finalSubtotal;
    const finalChange = Math.max(0, received - finalSubtotal);

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...currentCart],
      subtotal: finalSubtotal,
      discount: 0,
      discountType: 'percent' as const,
      total: finalSubtotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    return { total: finalSubtotal, received, change: finalChange };
  }, [addOrder, orders.length, storeConfig.queueEnabled]);

  const stopVoiceSession = useCallback(async () => {
    console.log("POS: Stopping Voice Session...");
    if (connectionTimeoutRef.current) clearTimeout(connectionTimeoutRef.current);
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);

    isVoiceActiveRef.current = false;
    setIsVoiceActive(false);
    setIsConnecting(false);
    setIsTalking(false);
    isTransitioningRef.current = false;
    setMicVolume(0);

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    if (inputContextRef.current) {
      try { await inputContextRef.current.close(); } catch(e) {}
      inputContextRef.current = null;
    }

    setVoiceLastAction(null);

    setTimeout(() => {
      if (recognitionRef.current && !isVoiceActiveRef.current) {
        try { recognitionRef.current.start(); } catch (e) {}
      }
    }, 1000);
  }, []);

  const startVoiceSession = async () => {
    if (isVoiceActiveRef.current || isTransitioningRef.current) return;

    isTransitioningRef.current = true;
    setIsConnecting(true);
    setIsVoiceActive(true);

    connectionTimeoutRef.current = setTimeout(() => {
      if (isConnecting && isVoiceActiveRef.current) {
        stopVoiceSession();
        alert("การเชื่อมต่อล้มเหลว กรุณาลองใหม่ครับ");
      }
    }, 15000);

    try {
      if (recognitionRef.current) {
        try { recognitionRef.current.stop(); } catch (e) {}
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }
      const outCtx = audioContextRef.current;
      if (outCtx.state === 'suspended') await outCtx.resume();

      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputContextRef.current = inCtx;

      const productListString = products.map(p => `- ${p.name} (ราคา ${p.price} บาท)`).join('\n');

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (connectionTimeoutRef.current) clearTimeout(connectionTimeoutRef.current);
            setIsConnecting(false);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'addToCartByName') {
                  const { productName, quantity } = fc.args as any;
                  const found = products.find(p => p.name.toLowerCase().includes(productName.toLowerCase()));
                  if (found) {
                    addToCart(found, quantity || 1);
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: "Success" } }
                    }));
                  } else {
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: "Not found" } }
                    }));
                  }
                } else if (fc.name === 'processCheckout') {
                  const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                  setPaymentMethod(pMethod);
                  finalizeOrder(pMethod, cashReceived);
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: "Success" } }
                  }));
                } else if (fc.name === 'closeMic') {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: "OK" } }
                  }));
                  setTimeout(stopVoiceSession, 1500);
                }
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outCtx.state !== 'closed') {
              setIsTalking(true);
              if (talkingTimeoutRef.current) clearTimeout(talkingTimeoutRef.current);

              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);
              source.onended = () => {
                talkingTimeoutRef.current = setTimeout(() => setIsTalking(false), 500);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
            }
          },
          onclose: stopVoiceSession,
          onerror: stopVoiceSession
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          systemInstruction: `คุณคือพนักงานขาย POS อัจฉริยะ (ชาย) สุภาพ ลงท้ายด้วยครับเสมอ
          รายการสินค้า:
          ${productListString}

          คำแนะนำ:
          1. ห้ามปิดการสนทนาหรือปิดไมโครโฟนจนกว่าลูกค้าจะพูดว่า "ขอบคุณมาก", "พอแค่นี้", "ปิดไมค์" หรือสั่งงานเสร็จสิ้นและยืนยันการชำระเงิน
          2. หากลูกค้าสั่งสินค้า ให้เรียก addToCartByName ทันทีและถามต่อว่า "รับอะไรเพิ่มอีกไหมครับ?"
          3. หากลูกค้าสั่งสรุปยอดหรือคิดเงิน ให้เรียก processCheckout
          4. หากลูกค้านิ่งเงียบไป ให้รอสักครู่แล้วถามว่า "ต้องการสั่งอะไรเพิ่มอีกไหมครับ?" หรือ "สะดวกชำระเงินเลยไหมครับ?"
          5. ทำงานอย่างเป็นกันเองและช่วยเสนอสินค้าหากลูกค้าไม่แน่ใจ`,
          tools: [{ functionDeclarations: [
            { name: 'addToCartByName', parameters: { type: Type.OBJECT, properties: { productName: { type: Type.STRING }, quantity: { type: Type.NUMBER } }, required: ['productName'] } },
            { name: 'processCheckout', parameters: { type: Type.OBJECT, properties: { cashReceived: { type: Type.NUMBER }, paymentMethod: { type: Type.STRING } }, required: ['paymentMethod'] } },
            { name: 'closeMic', parameters: { type: Type.OBJECT, properties: {} } }
          ] }]
        }
      });

      navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
        if (!isTransitioningRef.current) { stream.getTracks().forEach(t => t.stop()); return; }
        setIsConnecting(false); 
        isVoiceActiveRef.current = true;

        const source = inCtx.createMediaStreamSource(stream);

        // Setup visual analyser
        const analyser = inCtx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyserRef.current = analyser;

        const updateVolume = () => {
          if (!isVoiceActiveRef.current) return;
          const dataArray = new Uint8Array(analyser.frequencyBinCount);
          analyser.getByteFrequencyData(dataArray);
          let sum = 0;
          for (let i = 0; i < dataArray.length; i++) sum += dataArray[i];
          const average = sum / dataArray.length;
          setMicVolume(average);
          animationFrameRef.current = requestAnimationFrame(updateVolume);
        };
        updateVolume();

        const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessor.onaudioprocess = (e) => {
          if (!isVoiceActiveRef.current) return;
          const inputData = e.inputBuffer.getChannelData(0);
          const int16 = new Int16Array(inputData.length);
          for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
          sessionPromise.then(s => { 
            if (s) { 
              s.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }); 
            } 
          });
        };
        source.connect(scriptProcessor); 
        scriptProcessor.connect(inCtx.destination);
      }).catch(stopVoiceSession);

      sessionRef.current = await sessionPromise;
    } catch (err) { stopVoiceSession(); } finally { isTransitioningRef.current = false; }
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true; 
    recognition.lang = 'th-TH';
    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim().toLowerCase();
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActiveRef.current) startVoiceSession();
    };
    recognition.onend = () => { if (!isVoiceActiveRef.current && !isTransitioningRef.current) try { recognition.start(); } catch (err) {} };
    try { recognition.start(); } catch (e) {}
    recognitionRef.current = recognition;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, []);

  const change = useMemo(() => {
    const received = parseFloat(cashReceivedStr) || 0;
    return Math.max(0, received - subtotal);
  }, [cashReceivedStr, subtotal]);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">

      {/* Voice UI Overlay */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-3xl z-[150] flex flex-col items-center justify-center animate-in fade-in duration-500">
           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 animate-in zoom-in-95 w-full max-w-xl mx-4 relative overflow-hidden">
              {isConnecting ? (
                  <div className="flex flex-col items-center gap-8 py-10 w-full">
                     <Loader2 size={100} className="text-primary-500 animate-spin" />
                     <h2 className="text-3xl font-black text-slate-800 tracking-tight">กำลังเชื่อมต่อ AI...</h2>
                     <button onClick={stopVoiceSession} className="px-8 py-4 bg-slate-100 text-slate-500 rounded-3xl font-black text-lg hover:bg-slate-200 transition-all">ยกเลิก</button>
                  </div>
              ) : (
                <>
                  <div className="relative flex items-center justify-center">
                    {/* Visualizer Rings */}
                    <div 
                      className="absolute rounded-full bg-primary-100 transition-all duration-75"
                      style={{ 
                        width: `${128 + micVolume * 1.5}px`, 
                        height: `${128 + micVolume * 1.5}px`,
                        opacity: 0.3 + (micVolume / 100)
                      }}
                    />
                    <div 
                      className="absolute rounded-full bg-primary-200 transition-all duration-100"
                      style={{ 
                        width: `${128 + micVolume * 0.8}px`, 
                        height: `${128 + micVolume * 0.8}px`,
                        opacity: 0.2 + (micVolume / 150)
                      }}
                    />

                    <div className={`w-32 h-32 rounded-full flex items-center justify-center transition-all duration-500 z-10 ${isTalking ? 'bg-emerald-500 scale-110 shadow-2xl' : 'bg-primary-600 animate-pulse shadow-xl'}`}>
                        {isTalking ? <Volume2 size={64} className="text-white" /> : <Mic size={64} className="text-white" />}
                    </div>
                  </div>

                  <div className="text-center z-10">
                      <h2 className="text-4xl font-black text-slate-900 tracking-tight">
                        {isTalking ? "AI กำลังพูดกับคุณ..." : "กำลังฟังคุณอยู่ครับ"}
                      </h2>
                      <p className="text-slate-500 font-bold text-xl mt-2 italic">
                        {isTalking ? "กรุณารอสักครู่ครับ" : "บอกชื่อสินค้าที่ต้องการได้เลยครับ"}
                      </p>
                  </div>

                  {voiceLastAction && (
                      <div className="w-full bg-emerald-50 border-2 border-emerald-100 p-6 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4 z-10">
                          <CheckCircle size={32} className="text-emerald-500" />
                          <p className="text-xl font-black text-emerald-900">{voiceLastAction}</p>
                      </div>
                  )}

                  <div className="bg-slate-900 p-10 rounded-[3rem] text-center w-full shadow-2xl border border-slate-700 z-10">
                      <p className="text-xs text-slate-400 uppercase tracking-widest mb-2 font-bold">ยอดรวมในตะกร้าตอนนี้</p>
                      <p className="text-7xl font-black text-white tracking-tighter">
                        <span className="text-3xl mr-1 text-primary-400">{storeConfig.currency}</span>
                        {subtotal.toFixed(2)}
                      </p>
                  </div>

                  <button onClick={stopVoiceSession} className="w-full py-6 bg-red-50 text-red-600 rounded-[2.5rem] font-black text-2xl flex items-center justify-center gap-4 hover:bg-red-100 transition-all shadow-md active:scale-95 z-10">
                    <MicOff size={32}/> ปิดระบบสั่งงาน
                  </button>
                </>
              )}
           </div>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm border-b border-slate-100 flex items-center gap-4">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input type="text" placeholder="ค้นหาชื่อหรือสแกนสินค้า..." className="w-full pl-10 pr-4 py-3 border rounded-xl border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none text-lg transition-all" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} />
            </div>
            <button onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} className={`px-6 py-3 rounded-xl flex items-center gap-3 font-black transition-all shadow-md active:scale-95 border-2 ${isVoiceActive ? 'bg-primary-50 text-primary-600 border-primary-500' : 'bg-white text-slate-700 border-slate-200 hover:border-primary-200'}`}>
               {isConnecting ? <Loader2 size={20} className="animate-spin" /> : (isVoiceActive ? <MicOff size={22} /> : <Sparkles size={20} className="text-primary-500 animate-pulse" />)}
               <span>{isVoiceActive ? 'หยุดฟัง' : 'สั่งงานด้วยเสียง'}</span>
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6">
            {products.filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase())).map(product => (
              <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-start transition-all group ${product.stock === 0 ? 'opacity-50 grayscale cursor-not-allowed' : 'hover:shadow-xl hover:border-primary-100 active:scale-95'}`}>
                <div className="w-full aspect-square bg-slate-50 rounded-3xl mb-4 overflow-hidden border border-slate-50">
                   <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={product.name} />
                </div>
                <h3 className="font-bold text-slate-800 line-clamp-1 text-sm">{product.name}</h3>
                <span className="font-black text-primary-600 text-base">{storeConfig.currency}{product.price.toFixed(2)}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-6 border-b border-slate-100 flex justify-between bg-slate-50/40 items-center">
            <h2 className="font-black text-xl text-slate-800 flex items-center gap-2"><ShoppingCart size={24} className="text-primary-600"/> ตะกร้า</h2>
            <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:text-red-600 px-3 py-1.5 bg-red-50 rounded-full transition-all uppercase tracking-widest">ล้างออก</button>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4">
          {cart.map(item => (
            <div key={item.id} className="flex gap-4 bg-white p-4 rounded-[2rem] border border-slate-50 shadow-sm animate-in slide-in-from-right-4">
              <img src={item.image} className="w-14 h-14 rounded-2xl object-cover border border-slate-100" alt={item.name} />
              <div className="flex-1 min-w-0">
                <h4 className="text-xs font-black text-slate-800 truncate">{item.name}</h4>
                <div className="text-primary-600 font-black text-lg">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
              </div>
              <div className="flex items-center bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">
                  <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-white"><Minus size={14}/></button>
                  <span className="w-8 text-center text-xs font-black">{item.quantity}</span>
                  <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-white"><Plus size={14}/></button>
              </div>
            </div>
          ))}
        </div>
        <div className="p-8 bg-slate-900 text-white rounded-t-[3.5rem] shadow-2xl">
          <div className="flex justify-between text-3xl font-black mb-8 tracking-tighter">
            <span>สุทธิ</span>
            <span>{storeConfig.currency}{subtotal.toFixed(2)}</span>
          </div>
          <button onClick={() => { setIsCheckoutOpen(true); setCashReceivedStr(''); }} disabled={cart.length === 0} className="w-full bg-primary-500 hover:bg-primary-400 disabled:bg-slate-800 disabled:text-slate-600 text-white py-6 rounded-[2.2rem] font-black text-2xl shadow-xl transition-all active:scale-[0.98] flex items-center justify-center gap-4 uppercase">
            <Banknote size={30} /> ชำระเงิน
          </button>
        </div>
      </div>

      {/* Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 bg-slate-900/70 z-[160] flex items-center justify-center p-4 backdrop-blur-md animate-in fade-in">
          <div className="bg-white w-full max-w-2xl rounded-[3.5rem] shadow-2xl overflow-hidden p-10 relative animate-in zoom-in-95 flex flex-col max-h-[90vh]">
            <button onClick={() => { setIsCheckoutOpen(false); setCompletedOrder(null); }} className="absolute top-8 right-8 p-3 bg-slate-100 hover:bg-slate-200 rounded-full transition-colors text-slate-500 z-10">
               <X size={24} />
            </button>

            {completedOrder ? (
              <div className="space-y-8 text-center py-6 overflow-y-auto">
                <div className="w-32 h-32 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center animate-bounce mx-auto shadow-lg"><CheckCircle size={80} /></div>
                <h2 className="text-5xl font-black text-slate-900 tracking-tight">ชำระสำเร็จ!</h2>
                <div className="bg-slate-50 rounded-[2.5rem] p-10 border border-slate-100 shadow-inner">
                   <p className="text-slate-500 font-black text-sm uppercase mb-3">เงินทอน</p>
                   <span className="font-black text-emerald-600 text-7xl tracking-tighter">{storeConfig.currency}{completedOrder.change?.toFixed(2)}</span>
                </div>
                <button onClick={() => {setIsCheckoutOpen(false); setCompletedOrder(null);}} className="w-full bg-slate-900 text-white py-8 rounded-[2.5rem] font-black text-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest">ทำรายการถัดไป</button>
              </div>
            ) : (
              <div className="flex-1 flex flex-col overflow-hidden">
                <div className="text-center mb-6 shrink-0">
                    <p className="text-slate-400 font-black uppercase text-xs tracking-widest mb-1">ยอดชำระสุทธิ</p>
                    <h1 className="text-7xl font-black text-slate-900 tracking-tighter">{storeConfig.currency}{subtotal.toFixed(2)}</h1>
                </div>

                <div className="grid grid-cols-3 gap-3 mb-6 shrink-0">
                    {['cash', 'promptpay', 'transfer'].map(method => (
                        <button key={method} onClick={() => setPaymentMethod(method as any)} className={`flex flex-col items-center justify-center p-5 rounded-[2rem] border-4 transition-all gap-2 ${paymentMethod === method ? 'border-primary-500 bg-primary-50 text-primary-600 shadow-md' : 'border-slate-50 bg-white text-slate-400'}`}>
                            {method === 'cash' ? <Banknote size={28}/> : method === 'promptpay' ? <QrCode size={28}/> : <Landmark size={28}/>}
                            <span className="text-[10px] font-black uppercase tracking-widest">{method === 'cash' ? 'เงินสด' : method === 'promptpay' ? 'พร้อมเพย์' : 'โอนเงิน'}</span>
                        </button>
                    ))}
                </div>

                <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar space-y-4">
                  {paymentMethod === 'cash' && (
                    <div className="space-y-4 animate-in slide-in-from-bottom-2">
                       <div className="relative">
                          <p className="text-xs font-black text-slate-500 uppercase tracking-widest mb-2 ml-4">จำนวนเงินที่รับมา</p>
                          <input 
                             autoFocus
                             type="number" 
                             placeholder="0.00" 
                             className="w-full p-8 bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] text-center text-5xl font-black outline-none focus:border-primary-500 transition-all text-slate-800"
                             value={cashReceivedStr}
                             onChange={(e) => setCashReceivedStr(e.target.value)}
                          />
                          <button onClick={() => setCashReceivedStr('')} className="absolute right-6 top-14 text-slate-300 hover:text-slate-500"><Delete size={32}/></button>
                       </div>

                       <div className="grid grid-cols-4 gap-2">
                          {[20, 50, 100, 500, 1000].map(val => (
                             <button key={val} onClick={() => setCashReceivedStr(val.toString())} className="py-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-600 hover:bg-slate-50 shadow-sm">+{val}</button>
                          ))}
                          <button onClick={() => setCashReceivedStr(subtotal.toString())} className="col-span-2 py-3 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl font-bold">พอดี ({subtotal})</button>
                       </div>

                       <div className="flex justify-between items-center p-6 bg-emerald-50 rounded-[2rem] border border-emerald-100 shadow-sm">
                          <span className="font-bold text-emerald-800">เงินทอนที่คาดจำกัด:</span>
                          <span className="text-3xl font-black text-emerald-700 tracking-tighter">{storeConfig.currency}{change.toFixed(2)}</span>
                       </div>
                    </div>
                  )}

                  {paymentMethod === 'promptpay' && (
                    <div className="animate-in zoom-in-95 duration-300 flex flex-col items-center space-y-4 p-4">
                        <div className="bg-white p-6 rounded-[3rem] shadow-xl border-4 border-primary-500 w-full max-w-xs aspect-square flex items-center justify-center relative overflow-hidden">
                           {storeConfig.promptPayQr ? (
                             <img src={storeConfig.promptPayQr} className="w-full h-full object-contain" alt="PromptPay QR" />
                           ) : (
                             <div className="text-center text-slate-300 space-y-2">
                               <QrCode size={80} className="mx-auto opacity-20" />
                               <p className="text-xs font-black">ยังไม่ได้ตั้งค่า QR Code</p>
                             </div>
                           )}
                        </div>
                        <div className="bg-primary-50 p-4 rounded-2xl border border-primary-100 text-center w-full">
                           <p className="text-xs font-black text-primary-700 uppercase tracking-widest mb-1">สแกนชำระผ่าน PromptPay</p>
                           <p className="text-lg font-black text-slate-800">ยอดชำระ {storeConfig.currency}{subtotal.toFixed(2)}</p>
                        </div>
                    </div>
                  )}

                  {paymentMethod === 'transfer' && (
                    <div className="animate-in slide-in-from-bottom-2 duration-300 space-y-4 p-2">
                        <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-200 shadow-inner">
                           <div className="flex items-center gap-4 mb-6 pb-6 border-b border-slate-200">
                              <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center shadow-md border border-slate-100">
                                <Landmark size={32} className="text-primary-600" />
                              </div>
                              <div>
                                <h3 className="text-xl font-black text-slate-800">{storeConfig.bankName || 'ยังไม่ระบุธนาคาร'}</h3>
                                <p className="text-sm font-bold text-slate-500 italic">ช่องทางโอนเงินผ่านบัญชี</p>
                              </div>
                           </div>

                           <div className="space-y-6">
                              <div className="group relative">
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-2">เลขที่บัญชี</p>
                                <div className="flex items-center justify-between bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                                  <span className="text-2xl font-black text-slate-800 tracking-widest">{storeConfig.bankAccount || 'xxx-x-xxxxx-x'}</span>
                                  <button onClick={() => { if(storeConfig.bankAccount) navigator.clipboard.writeText(storeConfig.bankAccount); }} className="p-2 text-primary-500 hover:bg-primary-50 rounded-lg transition-all"><Copy size={20}/></button>
                                </div>
                              </div>

                              <div>
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-2">ชื่อบัญชี</p>
                                <div className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm">
                                  <span className="text-xl font-black text-slate-800">{storeConfig.bankAccountName || 'ยังไม่ระบุชื่อบัญชี'}</span>
                                </div>
                              </div>
                           </div>
                        </div>
                        <div className="p-4 bg-amber-50 rounded-2xl border border-amber-100 flex items-center gap-3">
                           <Info size={20} className="text-amber-500 shrink-0" />
                           <p className="text-xs font-bold text-amber-800">กรุณาตรวจสอบชื่อบัญชีและยอดโอนให้ตรงกับที่ระบุ</p>
                        </div>
                    </div>
                  )}
                </div>

                <button 
                   disabled={paymentMethod === 'cash' && (!cashReceivedStr || parseFloat(cashReceivedStr) < subtotal)}
                   onClick={() => finalizeOrder(paymentMethod, parseFloat(cashReceivedStr) || subtotal)} 
                   className="w-full bg-primary-600 disabled:bg-slate-300 text-white py-8 rounded-[2.5rem] font-black text-3xl shadow-xl transition-all active:scale-[0.98] uppercase mt-4 shrink-0 tracking-widest"
                >
                   ยืนยันการชำระ
                </button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default POS;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useStore } from '../context/StoreContext';
import { Product, CartItem, Order, Member, PaymentMethodType } from '../types';
import { Search, Trash2, Plus, Minus, CreditCard, Banknote, X, Printer, CheckCircle, ShoppingCart, ScanLine, TicketPercent, User, UserPlus, Gift, Link, Divide, Bell, Camera, Tag, Coins, Stamp, QrCode, Landmark, Wallet, Mic, MicOff, Volume2, Info, Sparkles, Loader2, VolumeX, Delete, Copy } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';

// --- Audio Helpers ---
function decode(base64: string) {
  try {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  } catch (e) {
    return new Uint8Array(0);
  }
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const POS: React.FC = () => {
  const { products, addOrder, storeConfig, orders } = useStore();
  const [cart, setCart] = useState<CartItem[]>([]);
  const cartRef = useRef<CartItem[]>([]);

  useEffect(() => {
    cartRef.current = cart;
  }, [cart]);

  const [searchQuery, setSearchQuery] = useState('');
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cash');
  const [cashReceivedStr, setCashReceivedStr] = useState('');
  const [completedOrder, setCompletedOrder] = useState<Order | null>(null);

  // Voice UI States
  const [isVoiceActive, setIsVoiceActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isTalking, setIsTalking] = useState(false);
  const [voiceLastAction, setVoiceLastAction] = useState<string | null>(null);
  const [micVolume, setMicVolume] = useState(0);

  // Refs for stability
  const isTransitioningRef = useRef(false);
  const isVoiceActiveRef = useRef(false);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const recognitionRef = useRef<any>(null);
  const nextStartTimeRef = useRef(0);
  const talkingTimeoutRef = useRef<any>(null);
  const connectionTimeoutRef = useRef<any>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  const subtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);

  const addToCart = useCallback((product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        if (existing.quantity + quantity > product.stock) return prev;
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item);
      }
      if (quantity > product.stock) return prev;
      return [...prev, { ...product, quantity }];
    });
    setVoiceLastAction(`เพิ่ม ${product.name} x${quantity}`);
    setTimeout(() => setVoiceLastAction(null), 5000);
  }, []);

  const updateQuantity = useCallback((id: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === id);
      if (!existing) return prev;
      const newQuantity = existing.quantity + delta;
      if (newQuantity <= 0) return prev.filter(item => item.id !== id);
      if (newQuantity > existing.stock) return prev;
      return prev.map(item => item.id === id ? { ...item, quantity: newQuantity } : item);
    });
  }, []);

  const finalizeOrder = useCallback((pMethod: PaymentMethodType = 'cash', pReceived?: number) => {
    const currentCart = cartRef.current;
    if (currentCart.length === 0) return { total: 0, received: 0, change: 0 };
    const finalSubtotal = currentCart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const received = pReceived !== undefined ? pReceived : finalSubtotal;
    const finalChange = Math.max(0, received - finalSubtotal);

    const newOrder: Order = {
      id: Date.now().toString(),
      items: [...currentCart],
      subtotal: finalSubtotal,
      discount: 0,
      discountType: 'percent' as const,
      total: finalSubtotal,
      paymentMethod: pMethod,
      timestamp: new Date().toISOString(),
      cashReceived: received,
      change: finalChange,
      status: storeConfig.queueEnabled ? 'preparing' : 'completed',
      queueNumber: storeConfig.queueEnabled ? orders.length + 1 : undefined
    };

    addOrder(newOrder);
    setCompletedOrder(newOrder);
    setCart([]);
    return { total: finalSubtotal, received, change: finalChange };
  }, [addOrder, orders.length, storeConfig.queueEnabled]);

  const stopVoiceSession = useCallback(async () => {
    if (connectionTimeoutRef.current) clearTimeout(connectionTimeoutRef.current);
    if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);

    isVoiceActiveRef.current = false;
    setIsVoiceActive(false);
    setIsConnecting(false);
    setIsTalking(false);
    isTransitioningRef.current = false;
    setMicVolume(0);

    if (sessionRef.current) {
      try { sessionRef.current.close(); } catch(e) {}
      sessionRef.current = null;
    }

    if (inputContextRef.current) {
      try { await inputContextRef.current.close(); } catch(e) {}
      inputContextRef.current = null;
    }

    setVoiceLastAction(null);

    // Restart the background "Wake Word" listener after a short delay
    setTimeout(() => {
      if (recognitionRef.current && !isVoiceActiveRef.current) {
        try { recognitionRef.current.start(); } catch (e) {}
      }
    }, 1000);
  }, []);

  const startVoiceSession = async () => {
    if (isVoiceActiveRef.current || isTransitioningRef.current) return;

    isTransitioningRef.current = true;
    setIsConnecting(true);
    setIsVoiceActive(true);

    connectionTimeoutRef.current = setTimeout(() => {
      if (isConnecting && isVoiceActiveRef.current) {
        stopVoiceSession();
        alert("การเชื่อมต่อล้มเหลว กรุณาลองใหม่ครับ");
      }
    }, 15000);

    try {
      if (recognitionRef.current) {
        try { recognitionRef.current.stop(); } catch (e) {}
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      if (!audioContextRef.current || audioContextRef.current.state === 'closed') {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }
      const outCtx = audioContextRef.current;
      if (outCtx.state === 'suspended') await outCtx.resume();

      const inCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputContextRef.current = inCtx;

      const productListString = products.map(p => `- ${p.name} (ราคา ${p.price} บาท)`).join('\n');

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            if (connectionTimeoutRef.current) clearTimeout(connectionTimeoutRef.current);
            setIsConnecting(false);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'addToCartByName') {
                  const { productName, quantity } = fc.args as any;
                  const found = products.find(p => p.name.toLowerCase().includes(productName.toLowerCase()));
                  if (found) {
                    addToCart(found, quantity || 1);
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: "Success" } }
                    }));
                  } else {
                    sessionPromise.then(s => s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: "Not found" } }
                    }));
                  }
                } else if (fc.name === 'processCheckout') {
                  const { cashReceived, paymentMethod: pMethod } = fc.args as any;
                  setPaymentMethod(pMethod);
                  finalizeOrder(pMethod, cashReceived);
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: "Success" } }
                  }));
                } else if (fc.name === 'closeMic') {
                  sessionPromise.then(s => s.sendToolResponse({
                    functionResponses: { id: fc.id, name: fc.name, response: { result: "OK" } }
                  }));
                  setTimeout(stopVoiceSession, 1000);
                }
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio && outCtx.state !== 'closed') {
              setIsTalking(true);
              if (talkingTimeoutRef.current) clearTimeout(talkingTimeoutRef.current);

              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);
              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);
              source.onended = () => {
                talkingTimeoutRef.current = setTimeout(() => setIsTalking(false), 500);
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
            }
          },
          onclose: stopVoiceSession,
          onerror: stopVoiceSession
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
          systemInstruction: `คุณคือพนักงานขาย POS อัจฉริยะชื่อ "โนว่า" สุภาพ ลงท้ายด้วยครับเสมอ
          รายการสินค้าในร้าน:
          ${productListString}

          กฎสำคัญ:
          1. ห้ามปิดการสนทนาเองเด็ดขาด แม้ลูกค้าจะเงียบไป ให้รอฟังต่อเสมอ
          2. หากลูกค้าพูดว่า "ปิดไมค์" หรือ "ขอบคุณมากครับ/ค่ะ" หรือ "พอแค่นี้" ให้เรียกฟังก์ชัน closeMic ทันที
          3. เมื่อลูกค้าสั่งสินค้า ให้เรียก addToCartByName ทันที แล้วถามต่อว่า "รับอะไรเพิ่มอีกไหมครับ?"
          4. หากลูกค้าสั่งสรุปยอด/คิดเงิน ให้เรียก processCheckout
          5. ให้บริการอย่างกระตือรือร้นและช่วยแนะนำสินค้าได้ถ้าลูกค้าต้องการ`,
          tools: [{ functionDeclarations: [
            { name: 'addToCartByName', parameters: { type: Type.OBJECT, properties: { productName: { type: Type.STRING }, quantity: { type: Type.NUMBER } }, required: ['productName'] } },
            { name: 'processCheckout', parameters: { type: Type.OBJECT, properties: { cashReceived: { type: Type.NUMBER }, paymentMethod: { type: Type.STRING } }, required: ['paymentMethod'] } },
            { name: 'closeMic', parameters: { type: Type.OBJECT, properties: {} } }
          ] }]
        }
      });

      navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
        if (!isTransitioningRef.current) { stream.getTracks().forEach(t => t.stop()); return; }
        setIsConnecting(false); 
        isVoiceActiveRef.current = true;

        const source = inCtx.createMediaStreamSource(stream);

        const analyser = inCtx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyserRef.current = analyser;

        const updateVolume = () => {
          if (!isVoiceActiveRef.current) return;
          const dataArray = new Uint8Array(analyser.frequencyBinCount);
          analyser.getByteFrequencyData(dataArray);
          let sum = 0;
          for (let i = 0; i < dataArray.length; i++) sum += dataArray[i];
          const average = sum / dataArray.length;
          setMicVolume(average);
          animationFrameRef.current = requestAnimationFrame(updateVolume);
        };
        updateVolume();

        const scriptProcessor = inCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessor.onaudioprocess = (e) => {
          if (!isVoiceActiveRef.current) return;
          const inputData = e.inputBuffer.getChannelData(0);
          const int16 = new Int16Array(inputData.length);
          for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
          sessionPromise.then(s => { 
            if (s) { 
              s.sendRealtimeInput({ media: { data: encode(new Uint8Array(int16.buffer)), mimeType: 'audio/pcm;rate=16000' } }); 
            } 
          });
        };
        source.connect(scriptProcessor); 
        scriptProcessor.connect(inCtx.destination);
      }).catch(stopVoiceSession);

      sessionRef.current = await sessionPromise;
    } catch (err) { stopVoiceSession(); } finally { isTransitioningRef.current = false; }
  };

  useEffect(() => {
    if (!('webkitSpeechRecognition' in window)) return;
    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = true; 
    recognition.lang = 'th-TH';
    recognition.onresult = (e: any) => {
      const text = e.results[e.results.length - 1][0].transcript.trim().toLowerCase();
      // Listen for Wake Phrase: "ใช้คำสั่งเสียง"
      if (text.includes("ใช้คำสั่งเสียง") && !isVoiceActiveRef.current) {
        startVoiceSession();
      }
    };
    recognition.onend = () => {
      // Keep background recognition alive as long as voice mode is NOT active
      if (!isVoiceActiveRef.current && !isTransitioningRef.current) {
        try { recognition.start(); } catch (err) {}
      }
    };
    try { recognition.start(); } catch (e) {}
    recognitionRef.current = recognition;
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, []);

  const change = useMemo(() => {
    const received = parseFloat(cashReceivedStr) || 0;
    return Math.max(0, received - subtotal);
  }, [cashReceivedStr, subtotal]);

  return (
    <div className="flex h-full bg-slate-100 overflow-hidden relative">

      {/* Voice UI Overlay */}
      {isVoiceActive && (
        <div className="fixed inset-0 bg-slate-900/98 backdrop-blur-3xl z-[150] flex flex-col items-center justify-center animate-in fade-in duration-500">
           <div className="bg-white p-12 rounded-[4rem] shadow-2xl flex flex-col items-center gap-10 border-4 border-primary-500 animate-in zoom-in-95 w-full max-w-xl mx-4 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-primary-500 via-indigo-500 to-primary-500 animate-pulse"></div>

              {isConnecting ? (
                  <div className="flex flex-col items-center gap-8 py-10 w-full">
                     <div className="relative">
                        <Loader2 size={100} className="text-primary-500 animate-spin" />
                        <Sparkles size={32} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-primary-300 animate-pulse" />
                     </div>
                     <h2 className="text-3xl font-black text-slate-800 tracking-tight">กำลังเริ่มระบบสั่งงานด้วยเสียง...</h2>
                     <button onClick={stopVoiceSession} className="px-8 py-4 bg-slate-100 text-slate-500 rounded-3xl font-black text-lg hover:bg-slate-200 transition-all">ยกเลิก</button>
                  </div>
              ) : (
                <>
                  <div className="relative flex items-center justify-center">
                    {/* Pulsing Visualizer Rings */}
                    <div 
                      className="absolute rounded-full bg-primary-100 transition-all duration-75"
                      style={{ 
                        width: `${140 + micVolume * 2}px`, 
                        height: `${140 + micVolume * 2}px`,
                        opacity: 0.2 + (micVolume / 100)
                      }}
                    />
                    <div 
                      className="absolute rounded-full bg-primary-200 transition-all duration-100"
                      style={{ 
                        width: `${140 + micVolume * 1}px`, 
                        height: `${140 + micVolume * 1}px`,
                        opacity: 0.1 + (micVolume / 150)
                      }}
                    />

                    <div className={`w-36 h-36 rounded-full flex items-center justify-center transition-all duration-500 z-10 shadow-2xl ${isTalking ? 'bg-emerald-500 scale-105' : 'bg-primary-600 animate-pulse'}`}>
                        {isTalking ? <Volume2 size={72} className="text-white" /> : <Mic size={72} className="text-white" />}
                    </div>
                  </div>

                  <div className="text-center z-10">
                      <h2 className="text-4xl font-black text-slate-900 tracking-tight">
                        {isTalking ? "โนว่ากำลังพูด..." : "บอกชื่อสินค้าได้เลยครับ"}
                      </h2>
                      <p className="text-slate-500 font-bold text-xl mt-3">
                        {isTalking ? "กรุณารอสักครู่ครับ" : "พูดว่า \"ปิดไมค์\" เมื่อสั่งงานเสร็จ"}
                      </p>
                  </div>

                  {voiceLastAction && (
                      <div className="w-full bg-emerald-50 border-2 border-emerald-100 p-6 rounded-[2.5rem] flex items-center gap-4 animate-in slide-in-from-top-4 z-10 shadow-sm">
                          <CheckCircle size={36} className="text-emerald-500" />
                          <p className="text-2xl font-black text-emerald-900">{voiceLastAction}</p>
                      </div>
                  )}

                  <div className="bg-slate-900 p-10 rounded-[3rem] text-center w-full shadow-2xl border border-slate-700 z-10">
                      <p className="text-[10px] text-slate-500 uppercase tracking-[0.3em] mb-3 font-black">Subtotal in Cart</p>
                      <p className="text-7xl font-black text-white tracking-tighter">
                        <span className="text-3xl mr-1 text-primary-400">{storeConfig.currency}</span>
                        {subtotal.toFixed(2)}
                      </p>
                  </div>

                  <button onClick={stopVoiceSession} className="w-full py-7 bg-red-50 text-red-600 rounded-[2.5rem] font-black text-2xl flex items-center justify-center gap-4 hover:bg-red-100 transition-all shadow-md active:scale-95 z-10">
                    <MicOff size={32}/> ปิดการสั่งงาน (ปิดไมค์)
                  </button>
                </>
              )}
           </div>
           <p className="mt-10 text-white/40 text-sm font-bold tracking-widest uppercase">Nova Voice AI System Active</p>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-full overflow-hidden">
        <div className="p-4 bg-white shadow-sm border-b border-slate-100 flex items-center gap-4 z-10">
            <div className="relative flex-1 group">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input type="text" placeholder="ค้นหาชื่อหรือสแกนสินค้า..." className="w-full pl-10 pr-4 py-3 border rounded-xl border-slate-200 focus:ring-2 focus:ring-primary-500 outline-none text-lg transition-all" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} />
            </div>
            <button 
              onClick={() => isVoiceActive ? stopVoiceSession() : startVoiceSession()} 
              className={`px-6 py-3 rounded-xl flex items-center gap-3 font-black transition-all shadow-lg active:scale-95 border-2 ${isVoiceActive ? 'bg-primary-50 text-primary-600 border-primary-500' : 'bg-white text-slate-700 border-slate-200 hover:border-primary-200'}`}
            >
               {isConnecting ? <Loader2 size={20} className="animate-spin" /> : (isVoiceActive ? <MicOff size={22} /> : <Sparkles size={20} className="text-primary-500 animate-pulse" />)}
               <span>{isVoiceActive ? 'ปิดไมค์' : 'ใช้คำสั่งเสียง'}</span>
            </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 scrollbar-hide">
          <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-6">
            {products.filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase())).map(product => (
              <button key={product.id} onClick={() => product.stock > 0 && addToCart(product)} className={`bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-start transition-all group ${product.stock === 0 ? 'opacity-50 grayscale cursor-not-allowed' : 'hover:shadow-xl hover:border-primary-100 active:scale-95'}`}>
                <div className="w-full aspect-square bg-slate-50 rounded-3xl mb-4 overflow-hidden border border-slate-50 relative">
                   <img src={product.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={product.name} />
                   {product.stock < storeConfig.lowStockThreshold && product.stock > 0 && (
                      <span className="absolute top-2 left-2 bg-amber-500 text-white text-[10px] font-black px-2 py-1 rounded-lg shadow-sm uppercase">Low Stock</span>
                   )}
                </div>
                <h3 className="font-bold text-slate-800 line-clamp-2 text-sm h-10 mb-1">{product.name}</h3>
                <span className="font-black text-primary-600 text-base">{storeConfig.currency}{product.price.toFixed(2)}</span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className="w-80 lg:w-96 bg-white border-l border-slate-200 flex flex-col h-full shadow-2xl z-20">
        <div className="p-6 border-b border-slate-100 flex justify-between bg-slate-50/40 items-center">
            <h2 className="font-black text-xl text-slate-800 flex items-center gap-2"><ShoppingCart size={24} className="text-primary-600"/> ตะกร้า</h2>
            <button onClick={() => setCart([])} className="text-[10px] font-black text-red-400 hover:text-red-600 px-3 py-1.5 bg-red-50 rounded-full transition-all uppercase tracking-widest">ล้างออก</button>
        </div>
        <div className="flex-1 overflow-y-auto p-5 space-y-4 scrollbar-hide">
          {cart.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-300 opacity-50">
              <ShoppingCart size={64} strokeWidth={1} className="mb-4" />
              <p className="font-bold">ตะกร้าว่างเปล่า</p>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex gap-4 bg-white p-4 rounded-[2rem] border border-slate-50 shadow-sm animate-in slide-in-from-right-4">
                <img src={item.image} className="w-14 h-14 rounded-2xl object-cover border border-slate-100" alt={item.name} />
                <div className="flex-1 min-w-0">
                  <h4 className="text-xs font-black text-slate-800 truncate">{item.name}</h4>
                  <div className="text-primary-600 font-black text-lg">{storeConfig.currency}{(item.price * item.quantity).toFixed(2)}</div>
                </div>
                <div className="flex items-center bg-slate-50 rounded-xl border border-slate-200 overflow-hidden">
                    <button onClick={() => updateQuantity(item.id, -1)} className="p-2 hover:bg-white"><Minus size={14}/></button>
                    <span className="w-8 text-center text-xs font-black">{item.quantity}</span>
                    <button onClick={() => updateQuantity(item.id, 1)} className="p-2 hover:bg-white"><Plus size={14}/></button>
                </div>
              </div>
            ))
          )}
        </div>
        <div className="p-8 bg-slate-900 text-white rounded-t-[3.5rem] shadow-2xl">
          <div className="flex justify-between text-3xl font-black mb-8 tracking-tighter">
            <span>สุทธิ</span>
